import type { SignTemplates } from './types';

export const leoTemplates: SignTemplates = {
  overall: {
    high: [
      { ko: '태양이 오늘 당신에게 모든 빛을 쏟아붓고 있습니다. 방에 들어서는 순간 사람들의 시선이 자연스럽게 당신에게 향하는 것을 느낄 것입니다. 이 왕의 기운을 부끄러워하지 말고 있는 그대로 빛나세요—그것이 바로 오늘 당신에게 주어진 사명입니다.', en: 'The sun pours all its light onto you today, and people\'s eyes will naturally turn to you the moment you enter a room. This royal energy is not meant to be hidden or dimmed. Let yourself shine exactly as you are—that is your mission today.', zh: '太阳今天将所有光芒倾泻于你。你踏入房间的那一刻，人们的目光会自然而然地聚向你。不要羞于这王者之气，就这样尽情绽放——这正是今天赋予你的使命。', ja: '太陽が今日あなたにすべての光を注いでいます。部屋に入った瞬間、人々の視線が自然とあなたに向くのを感じるでしょう。この王の気運を恥じずありのままに輝いてください——それが今日あなたに与えられた使命です。', es: 'El sol vierte toda su luz sobre ti hoy, y los ojos de las personas se dirigirán naturalmente a ti en cuanto entres a un lugar. No te avergüences de esta energía real. Brilla exactamente como eres—esa es tu misión de hoy.' },
      { ko: '당신의 카리스마가 정점에 달하는 날로, 사자자리의 자기장이 가장 강하게 펼쳐집니다. 주변 사람들이 당신의 말 한마디, 행동 하나에 집중하고 있으니 그 존재감을 충분히 활용하세요. 오늘만큼은 무대의 중심을 두려워하지 말고, 당신이 그 자리에 서야 할 이유가 있음을 확신하세요.', en: 'Your Leo magnetism reaches its absolute peak today, drawing everyone around you into your orbit without any effort. Every word you speak and every move you make will be noticed and remembered. Own the center of the stage without apology—you belong there today.', zh: '你的魅力今天达到顶点，狮子座的磁场最为强大地展开。周围的人都在关注你的一言一行，充分利用这种存在感吧。今天不要害怕成为舞台中心，相信自己站在那里自有其理由。', ja: 'あなたのカリスマが頂点に達する日で、獅子座の磁場が最も強く広がります。周りの人があなたの言葉一つ、行動一つに集中しているのでその存在感を十分に活用してください。今日だけはステージの中心を恐れず、あなたがそこに立つべき理由があると確信してください。', es: 'Tu magnetismo Leo alcanza su punto máximo hoy, atrayendo a todos a tu órbita sin esfuerzo. Cada palabra que digas y cada movimiento que hagas será notado y recordado. Ocupa el centro del escenario sin disculpas—hoy perteneces ahí.' },
      { ko: '불꽃 같은 자신감이 모든 장애물을 태워 없애는 날입니다. 당신이 불가능하다고 생각했던 것들이 오늘만큼은 현실이 될 수 있는 에너지가 충만합니다. 머뭇거림을 모두 내려놓고 지금 당장 전진하세요—우주가 당신의 등을 밀고 있습니다.', en: 'Flame-like confidence burns away every obstacle in your path today, and the energy to make the impossible possible is fully charged within you. Everything you\'ve been hesitating about can move forward right now. Let go of all hesitation and advance—the universe is pushing you forward.', zh: '如火焰般的自信今天烧尽所有障碍。你认为不可能的事情今天有能量变成现实。放下所有犹豫，立刻前进——宇宙正在推动你向前。', ja: '炎のような自信が全ての障害物を燃やし尽くす日です。あなたが不可能だと思っていたことが今日だけは現実になれるエネルギーが満ちています。ためらいを全て手放して今すぐ前進してください——宇宙があなたの背を押しています。', es: 'La confianza ardiente quema todos los obstáculos en tu camino hoy, y la energía para hacer lo imposible posible está completamente cargada en ti. Todo en lo que has dudado puede avanzar ahora mismo. Suelta toda vacilación y avanza—el universo te está empujando.' },
      { ko: '왕의 기운이 충만하여 당신이 내리는 모든 결정에 무게와 권위가 실립니다. 오늘은 오래 미뤄온 중요한 선택을 내리기에 이보다 더 좋은 날이 없습니다. 내면의 왕좌에 앉아 자신을 믿으세요—당신의 직관이 최선의 나침반입니다.', en: 'Royal energy fills you completely today, lending weight and authority to every decision you make. There is no better day to make the important choices you\'ve been postponing. Sit upon your inner throne and trust yourself—your intuition is your finest compass today.', zh: '王者之气充沛，你所做的每个决定都有分量和权威。今天是做出你一直推迟的重要选择的最佳时机。坐在你内心的王座上相信自己——你的直觉是今天最好的指南针。', ja: '王の気が充満しており、あなたが下す全ての決定に重みと権威が宿ります。今日は長く先送りにしてきた重要な選択を下すのにこれ以上良い日はありません。内なる王座に座り自分を信じてください——あなたの直感が最善の羅針盤です。', es: 'La energía real te llena completamente hoy, dando peso y autoridad a cada decisión que tomes. No hay mejor día para tomar las decisiones importantes que has estado posponiendo. Siéntate en tu trono interior y confía en ti—tu intuición es tu mejor brújula hoy.' },
      { ko: '당신의 존재만으로 주변이 밝아지는 오늘, 태양자리의 선물이 완전히 깨어났습니다. 특별한 노력 없이도 당신의 에너지가 사람들에게 희망과 활력을 전달합니다. 이 빛을 아끼지 말고 나눠주세요—줄수록 더 강하게 타오를 것입니다.', en: 'Today your presence alone brightens everything around you, as your solar gift has fully awakened. Without any special effort, your energy transmits hope and vitality to everyone nearby. Do not hold back this light—share it freely, for the more you give, the more intensely it blazes.', zh: '今天仅凭你的存在就能照亮周围，太阳座的天赋已完全觉醒。无需特别努力，你的能量就能向人们传递希望和活力。不要吝惜这道光，尽情分享——越给予，它燃烧得越旺盛。', ja: 'あなたの存在だけで周りが明るくなる今日、太陽座の贈り物が完全に目覚めました。特別な努力なしにあなたのエネルギーが人々に希望と活力を伝えます。この光を惜しまず分け与えてください——与えるほどより強く燃え上がるでしょう。', es: 'Hoy tu sola presencia ilumina todo a tu alrededor, pues tu don solar ha despertado completamente. Sin ningún esfuerzo especial, tu energía transmite esperanza y vitalidad a todos los cercanos. No retengas esta luz—compártela libremente, pues cuanto más das, más intensamente arde.' },
      { ko: '숨겨두었던 재능이 드디어 세상의 빛을 보는 날입니다. 당신 안에 오랫동안 잠들어 있던 능력이 지금 이 순간 깨어나 무대 위로 오르라고 손짓하고 있습니다. 두려움 없이 당당하게 그 자리에 서세요—세상은 당신의 빛을 기다리고 있었습니다.', en: 'Hidden talents finally emerge into the light of day, and the abilities that have long slept within you are awakening right now, beckoning you onto the stage. Step up to that place without fear or hesitation—the world has been waiting for your light all along.', zh: '隐藏的才能终于见到世界的光。你内心长久沉睡的能力此刻正在觉醒，向你招手让你登上舞台。无所畏惧地站上那个位置——世界一直在等待你的光芒。', ja: '隠していた才能がついに世の光を見る日です。あなたの中で長く眠っていた能力が今この瞬間目覚め、ステージに上がれと手招きしています。恐れることなく堂々とその場に立ってください——世界はずっとあなたの光を待っていました。', es: 'Los talentos ocultos finalmente salen a la luz del día, y las habilidades que han dormido dentro de ti durante tanto tiempo se despiertan ahora, llamándote al escenario. Ocupa ese lugar sin miedo ni vacilación—el mundo ha estado esperando tu luz todo este tiempo.' },
      { ko: '창조적 영감이 폭발하는 오늘, 머릿속에 떠오르는 아이디어들은 단순한 생각이 아닌 실제로 구현될 수 있는 씨앗들입니다. 사자자리의 창의력과 실행력이 동시에 활성화되어 있으니 생각에서 행동으로 즉시 넘어가세요. 오늘 시작하지 않으면 내일 후회할 바로 그 아이디어입니다.', en: 'Creative inspiration explodes today, and the ideas arising in your mind are not mere thoughts but seeds that can actually be realized. Your Leo creativity and drive are both fully activated, so move immediately from thought to action. This is exactly the idea you will regret not starting today.', zh: '创造性灵感今天爆发，脑海中浮现的想法不只是普通的念头，而是真正可以实现的种子。狮子座的创造力和执行力同时被激活，立刻从思考转向行动吧。这正是今天不开始明天就会后悔的那个想法。', ja: '創造的なインスピレーションが爆発する今日、頭の中に浮かぶアイデアは単なる考えではなく、実際に具現化できる種です。獅子座の創造力と実行力が同時に活性化されているので考えから行動へすぐに移ってください。今日始めなければ明日後悔する、まさにそのアイデアです。', es: 'La inspiración creativa explota hoy, y las ideas que surgen en tu mente no son simples pensamientos sino semillas que realmente pueden realizarse. Tu creatividad e impulso Leo están completamente activados, así que pasa inmediatamente del pensamiento a la acción. Esta es exactamente la idea que lamentarás no haber comenzado hoy.' },
      { ko: '오늘 시작하는 모든 일에 승리의 별이 함께하니, 이보다 더 좋은 출발의 기운은 없습니다. 두려움이란 당신이 얼마나 중요한 일을 시작하려 하는지를 보여주는 증거일 뿐입니다. 그 두려움을 용기의 연료로 바꾸어 첫 발을 내딛으세요—나머지는 우주가 도울 것입니다.', en: 'A star of victory accompanies everything you begin today, making this one of the finest moments for new starts. Fear is simply proof of how important the thing you are about to begin truly is. Transform that fear into fuel for courage and take the first step—the universe will handle the rest.', zh: '今天开始的所有事都有胜利之星相伴，没有比这更好的出发气运了。恐惧只不过是你即将开始多么重要的事情的证明。把恐惧转化为勇气的燃料，迈出第一步——其余的宇宙会来帮助。', ja: '今日始める全てのことに勝利の星が共にあり、これ以上良いスタートの気運はありません。恐れとはあなたがどれほど重要なことを始めようとしているかを示す証拠に過ぎません。その恐れを勇気の燃料に変えて第一歩を踏み出してください——残りは宇宙が助けてくれるでしょう。', es: 'Una estrella de victoria acompaña todo lo que comienzas hoy, haciendo de este uno de los mejores momentos para nuevos comienzos. El miedo es simplemente prueba de cuán importante es lo que estás a punto de comenzar. Transforma ese miedo en combustible para el valor y da el primer paso—el universo se encargará del resto.' },
      { ko: '당신의 관대함이 예상치 못한 행운으로 돌아오는 날입니다. 사자자리의 아량은 단순한 미덕이 아니라 우주의 풍요를 끌어당기는 자석입니다. 오늘 베풀수록 더 많이 채워지는 경험을 하게 될 것이니, 아낌없이 나눠주세요.', en: 'Your generosity returns as unexpected luck today, for Leo\'s magnanimity is not merely a virtue but a magnet that draws the universe\'s abundance toward you. The more you give today, the more you will experience being filled in return—so share without holding back.', zh: '你的慷慨今天以意想不到的好运回报。狮子座的大度不只是美德，更是吸引宇宙丰盛的磁铁。今天越给予，你就会越体验到被填满——所以尽情分享吧。', ja: 'あなたの寛大さが予想外の幸運として戻ってくる日です。獅子座の寛大さは単なる美徳ではなく、宇宙の豊かさを引き寄せる磁石です。今日は与えるほど満たされる経験をすることになるので惜しみなく分かち合ってください。', es: 'Tu generosidad regresa como suerte inesperada hoy, pues la magnanimidad de Leo no es solo una virtud sino un imán que atrae la abundancia del universo hacia ti. Cuanto más des hoy, más experimentarás ser llenado a cambio—así que comparte sin reservas.' },
      { ko: '진정한 리더의 면모가 빛나는 순간이 찾아왔습니다. 사람들은 당신이 말하기도 전에 이미 당신을 따르고 싶다는 느낌을 받고 있습니다. 이 자연스러운 권위를 겸손함과 함께 발휘하세요—진정한 왕은 군림하지 않고 이끕니다.', en: 'The moment when your true leadership shines has arrived, and people already feel drawn to follow you before you even speak. Exercise this natural authority alongside humility—a true king does not rule but leads, and today you are that king.', zh: '真正的领袖风范闪耀的时刻到来了。人们在你开口之前就已经感受到想追随你的冲动。以谦逊配合这种自然的权威——真正的王不是统治而是引领，今天你就是那位王。', ja: '真のリーダーの面目が輝く瞬間が訪れました。人々はあなたが話す前からすでにあなたについていきたいという感覚を受けています。この自然な権威を謙虚さとともに発揮してください——真の王は君臨せず率います、そして今日あなたがその王です。', es: 'Ha llegado el momento en que tu verdadero liderazgo brilla, y las personas ya se sienten atraídas a seguirte antes de que siquiera hables. Ejerce esta autoridad natural junto con la humildad—un verdadero rey no domina sino lidera, y hoy tú eres ese rey.' },
    ],
    medium: [
      { ko: '내면의 태양은 여전히 빛나고 있지만 오늘은 조용히 그 불꽃을 지키는 날입니다. 무대 위보다 무대 아래에서 에너지를 충전할 때, 내일의 빛이 더욱 강렬해집니다. 지금 이 고요함이 게으름이 아닌 현명한 준비임을 기억하세요.', en: 'Your inner sun still shines, but today is a day for quietly tending that flame rather than displaying it. When you recharge your energy below the stage rather than on it, tomorrow\'s light burns far more intensely. Remember that this quietness is not laziness—it is wise preparation.', zh: '内在的太阳依然闪耀，但今天是静静守护那火焰的日子。在舞台下而非舞台上补充能量时，明天的光芒会更加耀眼。记住，此刻的宁静不是懒惰，而是明智的准备。', ja: '内なる太陽はまだ輝いていますが今日は静かにその炎を守る日です。ステージの上よりステージの下でエネルギーを充電する時、明日の光がより強烈になります。今この静けさが怠惰ではなく賢明な準備であることを覚えておいてください。', es: 'Tu sol interior sigue brillando, pero hoy es un día para cuidar esa llama en silencio en vez de mostrarla. Cuando recargas tu energía por debajo del escenario en lugar de sobre él, la luz de mañana arde con mucha más intensidad. Recuerda que esta quietud no es pereza—es preparación sabia.' },
      { ko: '자존심을 살짝 내려놓으면 뜻밖의 문이 열리는 것을 경험하게 됩니다. 사자자리의 진정한 강함은 자신을 낮출 줄 아는 유연함에서 나옵니다. 겸손은 나약함이 아니라, 이미 충분히 강한 사람만이 선택할 수 있는 또 다른 힘입니다.', en: 'When you set your pride aside slightly, you will discover that unexpected doors swing open before you. Leo\'s true strength comes from the flexibility to know when to step back. Humility is not weakness—it is the kind of power that only those already strong enough can choose.', zh: '稍微放下自尊，你会发现意外的门在你面前打开。狮子座真正的强大来自知道何时退后的灵活性。谦逊不是软弱——它是只有已经足够强大的人才能选择的另一种力量。', ja: 'プライドを少し下ろすと思いがけない扉が開くことを経験します。獅子座の真の強さは引き下がるべき時を知る柔軟さから来ます。謙虚さは弱さではなく、すでに十分に強い人だけが選べるもう一つの力です。', es: 'Cuando dejas tu orgullo de lado ligeramente, descubrirás que puertas inesperadas se abren ante ti. La verdadera fortaleza de Leo viene de la flexibilidad de saber cuándo retroceder. La humildad no es debilidad—es el tipo de poder que solo quienes ya son suficientemente fuertes pueden elegir.' },
      { ko: '오늘은 무대 앞보다 무대 뒤에서 힘을 발휘하는 것이 훨씬 현명한 전략입니다. 숨겨진 영향력은 때로 가장 눈에 띄는 영향력보다 더 깊고 지속적입니다. 조용히 판을 움직이는 오늘의 당신은 내일의 더 큰 무대를 준비하고 있는 것입니다.', en: 'Today it is far wiser to exercise your power behind the scenes than at center stage. Hidden influence is sometimes deeper and more lasting than the most visible kind. As you quietly move the pieces today, you are in fact preparing for a much grander stage tomorrow.', zh: '今天在幕后发挥力量比站在中心舞台上要明智得多。隐藏的影响力有时比最显眼的影响力更深远持久。今天你悄悄地布局，其实是在为明天更大的舞台做准备。', ja: '今日はステージの中央よりも舞台裏で力を発揮する方がずっと賢明な戦略です。隠れた影響力は時に最も目立つ影響力より深く持続的です。今日静かに盤を動かすあなたは、明日のより大きな舞台を準備しているのです。', es: 'Hoy es mucho más sabio ejercer tu poder detrás del escenario que en el centro de él. La influencia oculta a veces es más profunda y duradera que la más visible. Al mover las piezas en silencio hoy, en realidad te estás preparando para un escenario mucho más grande mañana.' },
      { ko: '평소의 화려함 대신 차분한 접근이 더 좋은 결과를 가져오는 날입니다. 강물이 소리 없이 흘러도 결국 바다에 닿듯, 오늘의 절제된 에너지가 더 멀리 도달합니다. 자신의 리듬을 믿고 조용히, 하지만 확실하게 앞으로 나아가세요.', en: 'A calm approach brings better results than your usual flamboyance today. Just as a river reaches the ocean silently but surely, your measured energy today will reach farther. Trust your own rhythm and move forward quietly but with absolute certainty.', zh: '今天比起平时的华丽，沉稳的方式会带来更好的结果。就像河流无声地流淌却终究抵达大海，今天节制的能量会到达更远的地方。相信自己的节奏，安静但确定地向前走。', ja: '平常の華やかさの代わりに落ち着いたアプローチがより良い結果をもたらす日です。川が音なく流れても結局は海に届くように、今日の節制されたエネルギーがより遠くに届きます。自分のリズムを信じて静かに、しかし確実に前に進んでください。', es: 'Un enfoque tranquilo trae mejores resultados que tu habitual extravagancia hoy. Así como un río llega al océano en silencio pero con certeza, tu energía medida hoy llegará más lejos. Confía en tu propio ritmo y avanza en silencio pero con absoluta certeza.' },
      { ko: '사소한 일에 에너지를 낭비하면 정작 중요한 순간에 빛이 약해집니다. 오늘 당신의 불꽃은 유한하니, 진정 중요한 한 가지에 모든 에너지를 집중하세요. 선택과 집중이야말로 왕의 진정한 능력임을 잊지 마세요.', en: 'Wasting energy on trivial things dims your light exactly when you need it most. Your flame today is finite, so concentrate all your energy on the one thing that truly matters. Never forget that the ability to choose and focus is a king\'s truest power.', zh: '在琐事上浪费能量，到了真正重要的时刻光芒就会减弱。今天你的火焰是有限的，把所有能量集中在真正重要的那一件事上。别忘了选择与专注才是王者真正的能力。', ja: '些細なことにエネルギーを浪費すると肝心な瞬間に光が弱まります。今日あなたの炎は有限ですので、本当に重要な一つのことに全エネルギーを集中してください。選択と集中こそが王の真の能力であることを忘れないでください。', es: 'Gastar energía en cosas triviales atenúa tu luz exactamente cuando más la necesitas. Tu llama hoy es finita, así que concentra toda tu energía en la única cosa que realmente importa. Nunca olvides que la capacidad de elegir y enfocarse es el más verdadero poder de un rey.' },
      { ko: '주변의 조언에 귀를 기울이면 혼자서는 보지 못했던 전략이 보입니다. 왕에게도 현명한 참모가 필요하듯, 오늘은 자존심보다 열린 귀가 더 큰 자산입니다. 가장 현명한 리더는 자신이 모든 답을 알지 못함을 아는 사람입니다.', en: 'Listening to the advice around you will reveal strategies you could not see alone. Just as a king needs wise advisors, an open ear is a greater asset than pride today. The wisest leaders are those who know they do not have all the answers.', zh: '倾听周围的建议，你会看到独自看不见的策略。就像国王需要聪明的参谋一样，今天开放的耳朵比自尊心更有价值。最聪明的领导者是那些知道自己没有所有答案的人。', ja: '周りのアドバイスに耳を傾けると一人では見えなかった戦略が見えてきます。王にも賢明な参謀が必要なように、今日は自尊心より開かれた耳の方が大きな資産です。最も賢明なリーダーは自分が全ての答えを知っているわけではないと知っている人です。', es: 'Escuchar los consejos a tu alrededor te revelará estrategias que no podías ver solo. Así como un rey necesita consejeros sabios, un oído abierto es un activo mayor que el orgullo hoy. Los líderes más sabios son quienes saben que no tienen todas las respuestas.' },
      { ko: '완벽하지 않아도 괜찮은 날입니다. 지나치게 높은 기준이 오히려 창의력의 흐름을 막고 있을 수 있습니다. 오늘만큼은 결과보다 과정을 즐기는 여유를 가져보세요—그 자유로움 속에서 뜻밖의 걸작이 탄생합니다.', en: 'It is perfectly fine not to be perfect today. Excessively high standards may actually be blocking the natural flow of your creativity. Allow yourself to enjoy the process over the outcome just for today—it is within that freedom that unexpected masterpieces are born.', zh: '今天不完美也没关系。过高的标准可能反而阻碍了创意的流动。今天就享受过程胜于结果的从容吧——在那种自由中，意想不到的杰作会诞生。', ja: '完璧でなくても大丈夫な日です。あまりにも高い基準がかえって創造力の流れを妨げているかもしれません。今日だけは結果より過程を楽しむ余裕を持ってみてください——その自由さの中で思いがけない傑作が生まれます。', es: 'Está perfectamente bien no ser perfecto hoy. Los estándares excesivamente altos pueden estar bloqueando el flujo natural de tu creatividad. Permítete disfrutar el proceso sobre el resultado solo por hoy—es dentro de esa libertad donde nacen las obras maestras inesperadas.' },
      { ko: '고정궁의 고집이 발동하는 날이니, 상황이 예상과 다르게 흘러도 저항하지 마세요. 유연함은 약함이 아니라 지혜로운 적응입니다. 오늘 한 발짝 물러설 줄 아는 사자는 내일 더 크게 도약할 수 있습니다.', en: 'Fixed sign stubbornness may activate today, so when situations flow differently than expected, do not resist. Flexibility is not weakness but wise adaptation. A lion who knows how to step back today will make a far greater leap tomorrow.', zh: '今天固定宫的固执可能发作，所以当情况与预期不同时，不要抵抗。灵活是智慧的适应，不是软弱。今天懂得退后一步的狮子，明天能跳得更高更远。', ja: '固定宮の頑固さが発動する日なので、状況が予想と異なる流れになっても抵抗しないでください。柔軟さは弱さではなく賢明な適応です。今日一歩引くことを知るライオンは明日より大きく跳躍できます。', es: 'La terquedad del signo fijo puede activarse hoy, así que cuando las situaciones fluyan diferente a lo esperado, no resistas. La flexibilidad no es debilidad sino adaptación sabia. Un león que sabe retroceder hoy hará un salto mucho mayor mañana.' },
      { ko: '오늘은 이끌기보다 함께 걷는 것이 더 큰 힘을 발휘합니다. 혼자 앞서 달리는 리더보다 팀과 나란히 걷는 리더가 결국 더 멀리 나아갑니다. 협력의 가치를 발견하는 오늘이 당신의 리더십을 한 차원 높여줄 것입니다.', en: 'Walking together with others generates greater power than leading alone today. A leader who walks alongside the team ultimately goes farther than one who runs ahead alone. The value of cooperation you discover today will elevate your leadership to a whole new level.', zh: '今天与其领先，不如并肩同行更能发挥更大力量。与团队并肩而行的领导者，最终比独自领先的领导者走得更远。今天发现合作价值，会让你的领导力提升到新的维度。', ja: '今日は導くより一緒に歩く方がより大きな力を発揮します。一人で先に走るリーダーより、チームと並んで歩くリーダーが結局より遠くまで進みます。協力の価値を発見する今日があなたのリーダーシップを一段高めてくれるでしょう。', es: 'Caminar juntos con otros genera mayor poder que liderar solo hoy. Un líder que camina junto al equipo llega más lejos que uno que corre adelante solo. El valor de la cooperación que descubras hoy elevará tu liderazgo a un nivel completamente nuevo.' },
      { ko: '밖으로 향하던 에너지를 안으로 돌리는 오늘, 스스로도 몰랐던 내면의 깊이를 발견할 수 있습니다. 자기 성찰은 약함의 표시가 아니라 더 강해지기 위한 준비입니다. 지금 자신과 나누는 대화가 내일의 당신을 만들어갑니다.', en: 'As you turn your outward energy inward today, you may discover depths within yourself you never knew existed. Self-reflection is not a sign of weakness but preparation for becoming stronger. The conversation you have with yourself right now is shaping the person you will be tomorrow.', zh: '今天把向外的能量转向内在，你可能会发现自己从未知道的内心深处。自我反省不是软弱的表现，而是变得更强的准备。你现在与自己进行的对话，正在塑造明天的你。', ja: '外に向かっていたエネルギーを内に向ける今日、自分でも知らなかった内面の深さを発見できるかもしれません。自己省察は弱さの表れではなく、より強くなるための準備です。今自分と交わす対話が明日のあなたを作っていきます。', es: 'Al dirigir tu energía hacia adentro hoy, puedes descubrir profundidades dentro de ti que nunca supiste que existían. La autorreflexión no es signo de debilidad sino preparación para volverse más fuerte. La conversación que tienes contigo mismo ahora mismo está formando la persona que serás mañana.' },
    ],
    low: [
      { ko: '태양이 구름 뒤에 잠시 숨은 날은 누구에게나 찾아오는 자연스러운 주기입니다. 무리한 도전보다 충전의 시간을 갖는 것이 진정한 강자의 선택입니다. 오늘 쉬어간다는 것은 내일 더 밝게 빛나기 위한 현명한 준비임을 믿으세요.', en: 'Days when the sun hides behind clouds come as a natural cycle for everyone, including you. Choosing to recharge rather than push through difficult challenges is the decision of a truly strong person. Trust that resting today is wise preparation for shining even more brightly tomorrow.', zh: '太阳躲在云后的日子是每个人都会经历的自然周期。比起勉强挑战，选择充电才是真正强者的选择。相信今天的休息是为明天更亮地闪耀所做的明智准备。', ja: '太陽が雲の後ろに隠れる日は誰にでも訪れる自然なサイクルです。無理な挑戦より充電の時間を持つことが本当の強者の選択です。今日休むことが明日より明るく輝くための賢明な準備だと信じてください。', es: 'Los días en que el sol se oculta tras las nubes son un ciclo natural que le llega a todos, incluido a ti. Elegir recargar en vez de empujar a través de desafíos difíciles es la decisión de una persona verdaderamente fuerte. Confía en que descansar hoy es preparación sabia para brillar aún más mañana.' },
      { ko: '자존심이 앞서면 가장 소중한 것들이 조용히 멀어지는 날입니다. 오늘 한 발짝 물러서는 것은 패배가 아니라, 더 중요한 것을 지키는 용기입니다. 진정한 왕은 언제 전투를 피해야 하는지를 알고 있습니다.', en: 'When pride leads the way today, the most precious things quietly drift away. Stepping back just for today is not defeat but the courage to protect what matters most. A true king knows when to avoid the battle entirely.', zh: '今天自尊心先行，最珍贵的东西会悄悄地远去。今天退后一步不是失败，而是保护更重要事物的勇气。真正的王知道何时该避开战斗。', ja: 'プライドが先行すると最も大切なものが静かに遠ざかる日です。今日一歩引くことは敗北ではなく、より大切なものを守る勇気です。真の王はいつ戦いを避けるべきかを知っています。', es: 'Cuando el orgullo lidera hoy, las cosas más preciosas se alejan silenciosamente. Dar un paso atrás solo por hoy no es derrota sino el valor de proteger lo que más importa. Un verdadero rey sabe cuándo evitar la batalla por completo.' },
      { ko: '빛나고 싶은 욕구는 사자자리의 본능이지만, 오늘은 그 욕구를 조절하는 것이 더 지혜롭습니다. 그늘에서 쉬는 사자는 약한 것이 아니라 다음 도약을 준비하고 있는 것입니다. 오늘의 충분한 휴식이 내일의 당신을 더욱 강렬하게 빛나게 할 것입니다.', en: 'The desire to shine is Leo\'s instinct, but today it is wiser to moderate that urge. A lion resting in the shade is not weak—it is preparing for the next leap. Today\'s adequate rest will make tomorrow\'s version of you shine with even greater intensity.', zh: '想要闪耀的欲望是狮子座的本能，但今天调节那个欲望更为明智。在阴凉处休息的狮子不是软弱，而是在准备下一次飞跃。今天充足的休息会让明天的你更加耀眼地闪光。', ja: '輝きたい欲求は獅子座の本能ですが、今日はその欲求を調節する方がより賢明です。日陰で休むライオンは弱いのではなく、次の跳躍を準備しているのです。今日の十分な休息が明日のあなたをより強烈に輝かせるでしょう。', es: 'El deseo de brillar es el instinto de Leo, pero hoy es más sabio moderar ese impulso. Un león descansando en la sombra no es débil—está preparando el próximo salto. El descanso adecuado de hoy hará que la versión de ti de mañana brille con aún mayor intensidad.' },
      { ko: '모든 것을 혼자 해결하려는 오늘의 충동은 강함이 아니라 고집에서 나오는 것입니다. 도움을 요청하는 것은 나약함이 아니라 자원을 현명하게 활용하는 능력입니다. 진정한 리더는 혼자 모든 짐을 지지 않으며, 팀의 힘을 빌릴 줄 압니다.', en: 'The impulse to solve everything alone today comes not from strength but from stubbornness. Asking for help is not weakness but the ability to wisely leverage available resources. A true leader does not carry all the weight alone but knows how to draw on the strength of the team.', zh: '今天想要独自解决一切的冲动不是来自力量，而是来自固执。寻求帮助不是软弱，而是明智利用资源的能力。真正的领导者不会独自承担所有重担，而是懂得借助团队的力量。', ja: '今日全てを一人で解決しようとする衝動は強さではなく頑固さから来るものです。助けを求めることは弱さではなく資源を賢く活用する能力です。真のリーダーは一人で全ての荷を背負わず、チームの力を借りることを知っています。', es: 'El impulso de resolver todo solo hoy no viene de la fortaleza sino de la terquedad. Pedir ayuda no es debilidad sino la capacidad de aprovechar sabiamente los recursos disponibles. Un verdadero líder no carga todo el peso solo sino sabe cómo apoyarse en la fuerza del equipo.' },
      { ko: '충동적인 결정이 후회를 남기는 날입니다. 사자자리의 불꽃은 강렬하지만, 오늘은 그 열기를 식히고 최소 하루의 여유를 두고 판단하세요. 지금 당장 내리고 싶은 결정이 정말 옳은지, 내일 아침의 차가운 머리로 다시 생각해보세요.', en: 'Impulsive decisions leave regrets today. Leo\'s flame burns intensely, but cool that heat and give yourself at least a day before deciding. Whatever decision you want to make right now—revisit it tomorrow morning with a clear head and see if it still feels right.', zh: '今天冲动的决定会留下遗憾。狮子座的火焰燃烧得很强烈，但今天冷却那股热情，至少给自己一天时间再判断。现在想要做的决定是否真的正确？明天早上用冷静的头脑再想想。', ja: '衝動的な決定が後悔を残す日です。獅子座の炎は激しく燃えますが、今日はその熱気を冷まして最低一日の余裕を置いて判断してください。今すぐ下したい決定が本当に正しいか、明日の朝の冷静な頭でもう一度考えてみてください。', es: 'Las decisiones impulsivas dejan arrepentimiento hoy. La llama de Leo arde intensamente, pero enfría ese calor y date al menos un día antes de decidir. La decisión que quieres tomar ahora mismo—revisítala mañana por la mañana con la mente fría y ve si aún se siente correcta.' },
      { ko: '주변의 평가에 흔들리기 쉬운 날이지만, 당신의 본질적 가치는 타인의 시선이 결정하지 않습니다. 오늘 부정적인 평가를 들었더라도 그것이 당신이 누구인지를 정의하게 두지 마세요. 태양은 구름이 가렸다고 사라지지 않듯, 당신의 빛도 영원히 존재합니다.', en: 'You may be easily swayed by others\' opinions today, but your core value is not determined by the eyes of others. Even if you hear negative evaluations today, do not let them define who you are. Just as the sun does not disappear when clouds cover it, your light exists permanently.', zh: '今天容易被周围的评价动摇，但你本质的价值不是由他人的目光决定的。即使今天听到了负面评价，也不要让它定义你是谁。就像太阳被云遮住也不会消失，你的光永远存在。', ja: '周りの評価に揺れやすい日ですが、あなたの本質的な価値は他人の視線が決めるのではありません。今日否定的な評価を聞いたとしても、それがあなたが誰であるかを定義させないでください。太陽が雲に覆われても消えないように、あなたの光も永遠に存在します。', es: 'Puedes ser fácilmente influenciado por las opiniones de otros hoy, pero tu valor central no está determinado por los ojos ajenos. Incluso si escuchas evaluaciones negativas hoy, no dejes que definan quién eres. Así como el sol no desaparece cuando las nubes lo cubren, tu luz existe permanentemente.' },
      { ko: '에너지가 분산되기 쉬운 날이니, 오늘의 힘을 한 가지 중요한 일에 집중하는 것이 최선입니다. 여러 방향으로 타오르는 불꽃은 금세 꺼지지만, 한 점에 집중된 열은 강철도 녹입니다. 오늘 당신이 가장 원하는 그 한 가지에만 전부를 쏟아부으세요.', en: 'Energy scatters easily today, so directing all your power toward one important thing is your best strategy. Flames burning in many directions extinguish quickly, but heat concentrated at one point melts steel. Pour everything you have into that single thing you want most today.', zh: '今天能量容易分散，把今天的力量集中在一件重要的事情上是最好的策略。向多个方向燃烧的火焰很快就会熄灭，但集中在一点的热量能融化钢铁。今天把你所有的一切都倾注在你最想要的那一件事上。', ja: 'エネルギーが分散しやすい日なので、今日の力を一つの重要なことに集中するのが最善です。多くの方向に燃える炎はすぐに消えますが、一点に集中した熱は鉄も溶かします。今日あなたが最も望む一つのことだけに全てを注ぎ込んでください。', es: 'La energía se dispersa fácilmente hoy, así que dirigir todo tu poder hacia una cosa importante es tu mejor estrategia. Las llamas que arden en muchas direcciones se apagan rápidamente, pero el calor concentrado en un punto derrite el acero. Vierte todo lo que tienes en esa única cosa que más deseas hoy.' },
      { ko: '과도한 자신감이 판단력을 흐리게 만드는 날입니다. 지금 확신처럼 느껴지는 것이 사실은 충동일 수 있으니, 한 번 더 점검하는 신중함으로 무장하세요. 실수를 예방하는 작은 멈춤이 당신의 빛나는 평판을 지킵니다.', en: 'Excessive confidence may cloud your judgment today. What feels like certainty right now could actually be impulse, so arm yourself with the prudence to check one more time. A small pause to prevent mistakes protects your shining reputation.', zh: '今天过度的自信可能模糊判断力。现在感觉像确信的东西实际上可能是冲动，用再检查一次的谨慎来武装自己。防止失误的小小停顿保护你闪耀的声誉。', ja: '過度な自信が判断力を曇らせる日です。今確信のように感じることが実は衝動かもしれないので、もう一度確認する慎重さで武装してください。ミスを予防する小さな立ち止まりがあなたの輝く評判を守ります。', es: 'La confianza excesiva puede nublar tu juicio hoy. Lo que se siente como certeza ahora mismo podría ser en realidad impulso, así que ármate con la prudencia de verificar una vez más. Una pequeña pausa para prevenir errores protege tu brillante reputación.' },
      { ko: '고집을 부리면 상황이 악화되는 날입니다. 타협은 당신의 패배가 아니라, 더 큰 목표를 위해 지금 이 순간을 희생하는 전략적 선택입니다. 언젠가 왕도 협상 테이블에 앉아야 할 때가 있으며, 오늘이 바로 그 날입니다.', en: 'Stubbornness worsens the situation today. Compromise is not your defeat but a strategic choice to sacrifice this moment for a larger goal. Even a king must sometimes sit at the negotiation table, and today is exactly that day.', zh: '今天固执会让情况恶化。妥协不是你的失败，而是为了更大目标牺牲当下时刻的战略选择。国王有时也必须坐在谈判桌前，今天就是那一天。', ja: '頑固になると状況が悪化する日です。妥協はあなたの敗北ではなく、より大きな目標のために今この瞬間を犠牲にする戦略的選択です。いつか王も交渉テーブルに着かなければならない時がありますが、今日がまさにその日です。', es: 'La terquedad empeora la situación hoy. El compromiso no es tu derrota sino una elección estratégica de sacrificar este momento por un objetivo mayor. Incluso un rey a veces debe sentarse en la mesa de negociación, y hoy es exactamente ese día.' },
      { ko: '오늘은 왕좌에서 내려와 평범한 하루를 보내는 것이 최선의 선택입니다. 진정한 위대함은 높은 자리에 있을 때뿐 아니라 낮은 자리에서도 자신을 잃지 않을 때 완성됩니다. 오늘의 재충전이 내일의 당신을 더욱 빛나게 한다는 사실을 믿으세요.', en: 'Today the best choice is to step down from the throne and spend an ordinary day. True greatness is completed not only when on a high seat but when you do not lose yourself even on a low one. Trust that today\'s recharge will make tomorrow\'s version of you shine even more brilliantly.', zh: '今天最好的选择是从王座上下来，度过平凡的一天。真正的伟大不只在高位时，更在低位时也不失去自我时才得以完成。相信今天的充电会让明天的你更加耀眼地闪光。', ja: '今日は王座から降りて平凡な一日を過ごすことが最善の選択です。真の偉大さは高い地位にいる時だけでなく、低い地位にいても自分を失わない時に完成します。今日の充電が明日のあなたをさらに輝かせるという事実を信じてください。', es: 'Hoy la mejor opción es bajar del trono y pasar un día ordinario. La verdadera grandeza se completa no solo cuando estás en un lugar alto sino cuando no te pierdes a ti mismo incluso en uno bajo. Confía en que la recarga de hoy hará que la versión de ti de mañana brille aún más brillantemente.' },
    ],
  },
  love: {
    high: [
      { ko: '당신의 매력이 태양처럼 작열하는 오늘, 상대는 이미 당신에게 끌리고 있다는 것을 느끼고 있습니다. 사자자리의 따뜻하고 당당한 에너지가 사랑하는 사람의 마음을 완전히 사로잡는 힘을 가지고 있습니다. 오늘은 아낌없이 당신의 매력을 발산하세요.', en: 'Your charm blazes like the sun today, and the person you love already feels drawn to you. Leo\'s warm and confident energy has the power to completely captivate their heart. Today, radiate your charm without holding anything back.', zh: '今天你的魅力如太阳般炽热，对方已经感受到了对你的吸引。狮子座温暖自信的能量拥有完全俘获爱人心扉的力量。今天尽情散发你的魅力吧。', ja: 'あなたの魅力が太陽のように灼熱する今日、相手はすでにあなたに引き付けられていることを感じています。獅子座の温かく堂々とした エネルギーが愛する人の心を完全に捉える力を持っています。今日は惜しみなくあなたの魅力を発散してください。', es: 'Tu encanto arde como el sol hoy, y la persona que amas ya siente la atracción hacia ti. La energía cálida y segura de Leo tiene el poder de cautivar completamente su corazón. Hoy, irradia tu encanto sin retener nada.' },
      { ko: '드라마틱한 고백이 성공할 확률이 높은 날입니다. 사자자리의 당신은 감정을 크고 아름답게 표현하는 타고난 재능을 가지고 있습니다. 망설임은 이 순간을 놓치게 할 뿐이니, 용기 있게 마음을 전하세요—상대는 이미 당신의 진심을 기다리고 있을지도 모릅니다.', en: 'A dramatic confession has a high chance of success today. You as a Leo have the innate talent to express emotions in a grand and beautiful way. Hesitation will only make you miss this moment, so share your feelings courageously—your partner may already be waiting for your true feelings.', zh: '今天戏剧性的告白成功率很高。作为狮子座的你，天生具有宏大而美丽地表达情感的才能。犹豫只会让你错过这一刻，勇敢地传达心意吧——对方可能已经在等待你的真心了。', ja: 'ドラマチックな告白が成功する確率が高い日です。獅子座のあなたは感情を大きく美しく表現する生まれ持った才能を持っています。ためらいはこの瞬間を逃させるだけなので、勇気を持って気持ちを伝えてください——相手はすでにあなたの真心を待っているかもしれません。', es: 'Una confesión dramática tiene alta probabilidad de éxito hoy. Tú como Leo tienes el talento innato de expresar emociones de manera grandiosa y hermosa. La vacilación solo te hará perder este momento, así que comparte tus sentimientos con valentía—tu pareja puede ya estar esperando tus verdaderos sentimientos.' },
      { ko: '연인과의 관계가 한 단계 더 깊어지는 특별한 날입니다. 평소에 하지 못했던 진심 어린 대화를 꺼내보세요. 사자자리의 따뜻한 심장이 상대의 가슴에 닿을 때, 두 사람의 연결이 더욱 단단해집니다.', en: 'Today is a special day when your relationship with your loved one deepens to a new level. Bring up the heartfelt conversations you have not had before. When Leo\'s warm heart reaches your partner\'s chest, the connection between you two becomes even stronger.', zh: '今天是与恋人关系更进一步的特别日子。说出平时没能说的真心话吧。当狮子座温暖的心脏触动对方的内心时，两人的连接变得更加牢固。', ja: '恋人との関係が一段階さらに深まる特別な日です。普段できなかった真心のこもった会話を切り出してみてください。獅子座の温かい心臓が相手の胸に届く時、二人のつながりがさらに固くなります。', es: 'Hoy es un día especial cuando tu relación con tu ser amado se profundiza a un nuevo nivel. Trae las conversaciones sinceras que no has tenido antes. Cuando el cálido corazón de Leo llega al pecho de tu pareja, la conexión entre ustedes dos se vuelve aún más fuerte.' },
      { ko: '당신의 따뜻한 관대함에 상대가 깊이 감동받는 날입니다. 사자자리는 사랑할 때 태양처럼 베풀고, 그 넉넉함이 상대의 마음을 영원히 머물게 합니다. 오늘은 아낌없이 사랑을 표현하세요—받은 것보다 더 많이 돌아올 것입니다.', en: 'Your warm generosity deeply moves your partner today. Leo loves like the sun gives, and that abundance makes your partner\'s heart stay forever. Express love generously today—what returns to you will be even more than what you gave.', zh: '今天你温暖的慷慨深深打动对方。狮子座爱起来就像太阳给予一样，那种丰盛让对方的心永远停留。今天毫不吝啬地表达爱——回报给你的会比你给出的更多。', ja: 'あなたの温かい寛大さに相手が深く感動する日です。獅子座は愛する時太陽のように与え、その豊かさが相手の心を永遠に留まらせます。今日は惜しみなく愛を表現してください——受け取ったものより多く戻ってくるでしょう。', es: 'Tu cálida generosidad conmueve profundamente a tu pareja hoy. Leo ama como el sol da, y esa abundancia hace que el corazón de tu pareja se quede para siempre. Expresa amor generosamente hoy—lo que te regresa será incluso más de lo que diste.' },
      { ko: '운명적인 만남이 기다리고 있는 날입니다. 오늘 집에만 머물면 우주가 준비한 인연을 놓치게 됩니다. 밖으로 나가 새로운 에너지 속에 자신을 두세요—예상치 못한 곳에서 특별한 인연이 시작될 수 있습니다.', en: 'A fateful encounter is waiting for you today. If you stay home today, you will miss the connection the universe has prepared. Go out and place yourself among new energy—an unexpected and special connection can begin where you least expect it.', zh: '今天命运般的邂逅在等待你。如果今天待在家里，你会错过宇宙准备好的缘分。走出去，置身于新的能量中——特别的缘分可能在你意想不到的地方开始。', ja: '運命的な出会いが待っている日です。今日家にいるだけだと宇宙が準備した縁を逃すことになります。外に出て新しいエネルギーの中に自分を置いてください——予想外の場所で特別な縁が始まるかもしれません。', es: 'Un encuentro del destino te está esperando hoy. Si te quedas en casa hoy, perderás la conexión que el universo ha preparado. Sal y colócate entre nueva energía—una conexión especial inesperada puede comenzar donde menos lo esperas.' },
      { ko: '뜨거운 열정이 관계에 새로운 활력을 불어넣는 날입니다. 매너리즘에 빠진 관계도 오늘의 사자자리 불꽃이 다시 살아나게 만들 수 있습니다. 함께 특별한 시간을 만드세요—그 기억이 두 사람의 관계를 새로운 차원으로 끌어올릴 것입니다.', en: 'Hot passion breathes new vitality into your relationship today. Even a relationship that has fallen into routine can be reignited by Leo\'s flame today. Create special moments together—those memories will elevate your relationship to a whole new dimension.', zh: '炽热的激情今天为关系注入新活力。即使陷入一成不变的关系，今天狮子座的火焰也能重新点燃。一起创造特别的时光——那些记忆将把两人的关系提升到新的维度。', ja: '熱い情熱が関係に新しい活力を吹き込む日です。マンネリに陥った関係も今日の獅子座の炎が再び生き返らせることができます。一緒に特別な時間を作ってください——その記憶が二人の関係を新しい次元に引き上げるでしょう。', es: 'La pasión ardiente insufla nueva vitalidad a tu relación hoy. Incluso una relación que ha caído en la rutina puede ser reavivada por la llama de Leo hoy. Creen momentos especiales juntos—esos recuerdos elevarán su relación a una dimensión completamente nueva.' },
      { ko: '사랑하는 사람을 위해 빛나는 이벤트를 계획하면 잊지 못할 감동의 순간이 됩니다. 사자자리는 사랑을 표현할 때도 웅장하게 하는 것을 타고났으니, 오늘은 그 재능을 마음껏 발휘하세요. 상대는 당신의 이 특별한 노력을 평생 기억할 것입니다.', en: 'Planning a shining event for your loved one creates an unforgettable moment of deep emotion. Leo is born to express love in a grand way, so unleash that talent fully today. Your partner will remember this special effort for the rest of their life.', zh: '为爱人计划一个闪亮的活动，将成为难以忘怀的感动瞬间。狮子座天生就善于宏大地表达爱，今天尽情发挥那份才能。对方将永远记住你的这份特别用心。', ja: '愛する人のために輝くイベントを計画すると忘れられない感動の瞬間になります。獅子座は愛を表現する時も壮大に行うことを生まれながらに持っているので、今日はその才能を思い切り発揮してください。相手はあなたのこの特別な努力を一生覚えているでしょう。', es: 'Planear un evento brillante para tu ser amado crea un momento de profunda emoción que no se olvidará. Leo nace para expresar el amor de manera grandiosa, así que desata ese talento completamente hoy. Tu pareja recordará este esfuerzo especial por el resto de su vida.' },
      { ko: '당신의 충성심과 헌신이 드디어 보답받는 날입니다. 사자자리의 사랑은 한번 마음을 주면 끝까지 지키는 깊은 신뢰를 낳습니다. 오늘 형성되는 유대는 오랫동안 두 사람의 관계를 든든하게 받쳐줄 기둥이 될 것입니다.', en: 'Your loyalty and devotion are finally rewarded today. Leo\'s love creates a deep trust that, once given, remains steadfast to the end. The bond that forms today will become a pillar that supports your relationship firmly for a long time to come.', zh: '你的忠诚和奉献终于在今天得到回报。狮子座的爱一旦给出，就会产生坚守到底的深厚信任。今天形成的纽带将成为长期支撑两人关系的坚实支柱。', ja: 'あなたの忠誠心と献身がついに報われる日です。獅子座の愛は一度心を与えると最後まで守る深い信頼を生みます。今日形成される絆は長い間二人の関係をしっかりと支える柱になるでしょう。', es: 'Tu lealtad y dedicación finalmente son recompensadas hoy. El amor de Leo crea una confianza profunda que, una vez dada, se mantiene firme hasta el final. El vínculo que se forma hoy se convertirá en un pilar que apoyará su relación firmemente por mucho tiempo.' },
      { ko: '자신을 있는 그대로 보여주는 것이 가장 강력한 매력이 되는 날입니다. 완벽하게 꾸미지 않아도, 당신의 진정한 모습이 상대의 마음을 가장 깊이 움직입니다. 오늘은 모든 가면을 내려놓고 진짜 당신으로 사랑하세요.', en: 'Showing yourself exactly as you are becomes the most powerful attraction today. Even without perfect presentation, your true self moves your partner\'s heart most deeply. Today, set down every mask and love as the real you.', zh: '今天展示真实自我成为最强大的魅力。即使没有完美的装扮，你真实的样子也最深地打动对方的心。今天放下所有面具，以真实的你去爱。', ja: 'ありのままの自分を見せることが最も強力な魅力になる日です。完璧に着飾らなくても、あなたの真の姿が相手の心を最も深く動かします。今日は全ての仮面を降ろして本当のあなたとして愛してください。', es: 'Mostrarte exactamente como eres se convierte en la atracción más poderosa hoy. Incluso sin una presentación perfecta, tu yo verdadero mueve el corazón de tu pareja más profundamente. Hoy, deja caer cada máscara y ama como el verdadero tú.' },
      { ko: '사랑의 무대에서 주인공이 되는 날입니다. 사자자리에게 로맨스는 그냥 감정이 아니라 예술이며, 오늘 그 예술이 꽃처럼 활짝 피어납니다. 이 아름다운 에너지를 두 손으로 받아들이고 사랑의 주인공으로서 오늘을 살아가세요.', en: 'Today you become the star on the stage of love. For Leo, romance is not just an emotion but an art form, and today that art blooms like a flower in full bloom. Receive this beautiful energy with both hands and live today as the protagonist of love.', zh: '今天你成为爱情舞台上的主角。对狮子座来说，浪漫不只是情感，更是一门艺术，今天那门艺术如花朵般盛开。用双手接住这美好的能量，以爱情主角的身份度过今天。', ja: '愛のステージで主人公になる日です。獅子座にとってロマンスは単なる感情ではなく芸術であり、今日その芸術が花のように満開になります。この美しいエネルギーを両手で受け取り愛の主人公として今日を生きてください。', es: 'Hoy te conviertes en el protagonista en el escenario del amor. Para Leo, el romance no es solo una emoción sino una forma de arte, y hoy ese arte florece como una flor en plena floración. Recibe esta energía hermosa con ambas manos y vive hoy como el protagonista del amor.' },
    ],
    medium: [
      { ko: '사랑에도 겸손이 필요한 날입니다. 오늘만큼은 먼저 말하기보다 상대의 이야기에 귀를 기울여 보세요. 들어주는 것이 말해주는 것보다 더 깊은 사랑을 전달할 때가 있습니다.', en: 'A day when humility in love is needed. Today, try listening to your partner\'s story before speaking your own. There are times when listening conveys deeper love than any words you might offer.', zh: '爱情也需要谦逊的一天。今天试着先倾听对方的故事，而不是先开口说话。有时候倾听比说话能传递更深的爱。', ja: '愛にも謙虚さが必要な日です。今日だけは先に話すより相手の話に耳を傾けてみてください。聴いてあげることが話してあげることよりも深い愛を伝える時があります。', es: 'Un día en que se necesita humildad en el amor. Hoy, intenta escuchar la historia de tu pareja antes de hablar. A veces escuchar transmite un amor más profundo que cualquier palabra que puedas ofrecer.' },
      { ko: '관계에서 주도권보다 조화를 추구하면 더 깊은 유대가 생깁니다. 사자자리는 자연스럽게 이끌려 하지만 오늘은 두 사람이 함께 방향을 결정하는 경험을 해보세요. 나란히 걷는 두 사람이 결국 더 멀리, 더 오래 함께할 수 있습니다.', en: 'Seeking harmony over dominance creates deeper bonds in your relationship. Leo naturally tends to lead, but try the experience of deciding direction together as two equals today. Two people walking side by side ultimately go farther and stay together longer.', zh: '在关系中追求和谐而非主导权，会产生更深的纽带。狮子座自然倾向于引领，但今天尝试作为平等的两个人共同决定方向。并肩而行的两个人最终能走得更远，待在一起更久。', ja: '関係で主導権より調和を追求するとより深い絆が生まれます。獅子座は自然に導こうとしますが、今日は二人が一緒に方向を決める経験をしてみてください。並んで歩く二人が結局より遠くへ、より長く一緒にいられます。', es: 'Buscar armonía sobre el dominio crea vínculos más profundos en tu relación. Leo tiende naturalmente a liderar, pero prueba la experiencia de decidir la dirección juntos como dos iguales hoy. Dos personas caminando lado a lado en última instancia van más lejos y permanecen juntas por más tiempo.' },
      { ko: '상대를 내 기준에 맞추려 하기보다 있는 그대로 존중하는 연습이 필요한 날입니다. 사자자리의 높은 기준은 장점이지만, 사랑하는 사람에게 그 잣대를 들이밀면 상대가 숨이 막힙니다. 오늘은 상대의 다름을 아름다움으로 받아들여보세요.', en: 'Today calls for practicing respect for your partner as they are rather than trying to fit them to your standards. Leo\'s high standards are a strength, but applying that measuring stick to a loved one leaves them gasping for air. Today, receive your partner\'s differences as a form of beauty.', zh: '今天需要练习尊重对方本来的样子，而不是试图让对方符合你的标准。狮子座的高标准是优点，但对爱人动用那把尺子会让对方喘不过气。今天，把对方的不同当作一种美来接受吧。', ja: '相手を自分の基準に合わせようとするよりありのまま尊重する練習が必要な日です。獅子座の高い基準は長所ですが、愛する人にその基準を当てると相手が息苦しくなります。今日は相手の違いを美しさとして受け入れてみてください。', es: 'Hoy llama a practicar el respeto a tu pareja tal como es en vez de tratar de ajustarla a tus estándares. Los altos estándares de Leo son una fortaleza, pero aplicar esa vara de medir a alguien amado los deja sin aire. Hoy, recibe las diferencias de tu pareja como una forma de belleza.' },
      { ko: '화려한 이벤트 대신 소박한 일상의 따뜻함이 마음을 더 깊이 움직이는 날입니다. 거창한 제스처가 아닌 아침 커피 한 잔, 따뜻한 눈빛 하나가 오늘 상대의 가슴에 더 오래 남습니다. 사랑은 크기가 아니라 진심의 깊이로 측정됩니다.', en: 'Simple daily warmth moves hearts more deeply than flashy events today. Not a grand gesture but a morning cup of coffee, a warm gaze—these are what will linger in your partner\'s heart longer today. Love is measured not by its size but by the depth of sincerity.', zh: '今天比起华丽的活动，朴素日常的温暖更能深深打动人心。不是宏大的姿态，而是一杯早晨的咖啡、一个温暖的眼神，今天这些会在对方心中留存更久。爱不是以大小衡量，而是以真诚的深度衡量。', ja: '華やかなイベントの代わりに素朴な日常の温かさが心をより深く動かす日です。壮大なジェスチャーではなく朝のコーヒー一杯、温かい視線一つが今日相手の胸により長く残ります。愛は大きさではなく真心の深さで測られます。', es: 'La calidez cotidiana simple mueve corazones más profundamente que los eventos llamativos hoy. No un gran gesto sino una taza de café matutino, una mirada cálida—estas son las que permanecerán más tiempo en el corazón de tu pareja hoy. El amor se mide no por su tamaño sino por la profundidad de la sinceridad.' },
      { ko: '연인에게 작은 칭찬 한마디가 큰 선물보다 깊은 감동을 줄 수 있는 날입니다. 상대가 오늘 어떤 점에서 특별히 빛나는지 찾아서 진심으로 말해주세요. 그 한마디가 상대를 온종일 미소 짓게 할 것입니다.', en: 'A small compliment to your partner can be more touching than a big gift today. Find what makes your partner shine especially today and tell them sincerely. That single sentence will make your partner smile all day long.', zh: '今天给恋人一句小赞美可能比大礼物更令人感动。找出对方今天特别闪耀的地方，真诚地说出来。那一句话会让对方整天都在微笑。', ja: '恋人への小さな褒め言葉が大きなプレゼントより深い感動を与えることがある日です。相手が今日どんな点で特別に輝いているかを見つけて真心を込めて伝えてください。その一言が相手を一日中笑顔にさせるでしょう。', es: 'Un pequeño cumplido a tu pareja puede ser más conmovedor que un gran regalo hoy. Encuentra qué hace brillar especialmente a tu pareja hoy y díselo sinceramente. Esa única oración hará sonreír a tu pareja todo el día.' },
      { ko: '혼자만의 시간도 관계의 건강에 도움이 됩니다. 사랑하는 사람과 함께 있고 싶은 마음은 자연스럽지만, 오늘은 각자의 공간을 존중하며 적절한 거리를 유지해보세요. 숨을 쉴 수 있는 공간이 있어야 사랑도 더 오래 지속됩니다.', en: 'Alone time also helps relationship health. The desire to be with your loved one is natural, but today try respecting each other\'s space and maintaining appropriate distance. Love also lasts longer when there is room to breathe.', zh: '独处时间也有助于关系健康。想和爱人在一起的心是自然的，但今天试着尊重各自的空间，保持适当的距离。有能呼吸的空间，爱情才能持续更久。', ja: '一人の時間も関係の健康に役立ちます。愛する人と一緒にいたい気持ちは自然ですが、今日はお互いの空間を尊重して適切な距離を保ってみてください。呼吸できる空間があってこそ愛も長く続きます。', es: 'El tiempo a solas también ayuda a la salud de la relación. El deseo de estar con tu ser amado es natural, pero hoy intenta respetar el espacio de cada uno y mantener una distancia apropiada. El amor también dura más cuando hay espacio para respirar.' },
      { ko: '사랑을 독점하려는 마음을 살짝 내려놓으면 관계가 더 자유롭고 아름다워집니다. 새장 속의 새는 당신의 것이 되지 않으며, 자유롭게 날아다니다 스스로 돌아오는 새가 진정 당신 곁에 있는 것입니다. 오늘 그 믿음을 실험해보세요.', en: 'Releasing the desire to monopolize love slightly makes the relationship freer and more beautiful. A bird in a cage does not truly belong to you—the bird that flies freely and returns on its own is the one truly by your side. Experiment with that trust today.', zh: '稍微放下独占爱情的心，关系会更加自由美好。笼中的鸟不会真正属于你——自由飞翔后自己回来的鸟才是真正在你身边的。今天试试那份信任吧。', ja: '愛を独占しようとする気持ちを少し手放すと関係がより自由で美しくなります。かごの中の鳥はあなたのものにならず、自由に飛び回って自ら戻ってくる鳥が本当にあなたのそばにいるのです。今日その信頼を実験してみてください。', es: 'Soltar ligeramente el deseo de monopolizar el amor hace la relación más libre y hermosa. Un pájaro en una jaula no te pertenece verdaderamente—el pájaro que vuela libremente y regresa por su cuenta es el que genuinamente está a tu lado. Experimenta con esa confianza hoy.' },
      { ko: '오늘은 사랑의 불꽃보다 따스한 촛불 같은 대화가 훨씬 더 어울리는 하루입니다. 강렬함보다 조용한 따뜻함이 상대의 마음에 더 깊이 스며드는 날이니, 대화의 온도를 낮추고 마음을 열어보세요. 불꽃은 잠시 타오르지만 촛불은 오랫동안 빛납니다.', en: 'Today warm candlelight-like conversations suit much better than fiery passion. This is a day when quiet warmth seeps deeper into your partner\'s heart than intensity, so lower the temperature of conversation and open your heart. Flames burn for a moment but candlelight shines for a long time.', zh: '今天比起爱情的火焰，温暖的烛光般的对话更加合适。比强烈更安静的温暖会更深地渗入对方心中，所以降低对话的温度，打开心扉。火焰只燃烧一时，但烛光长久地照耀。', ja: '今日は愛の炎より温かいキャンドルのような対話がずっと似合う一日です。強烈さより静かな温かさが相手の心に深く染み込む日なので、対話の温度を下げて心を開いてみてください。炎はしばらく燃え上がりますがキャンドルは長く輝きます。', es: 'Hoy las conversaciones cálidas como la luz de una vela se adaptan mucho mejor que la pasión ardiente. Este es un día cuando la calidez tranquila penetra más profundamente en el corazón de tu pareja que la intensidad, así que baja la temperatura de la conversación y abre tu corazón. Las llamas arden por un momento pero la luz de las velas brilla durante mucho tiempo.' },
      { ko: '연인과의 사소한 의견 차이는 관계를 더 깊게 이해하는 성장의 기회입니다. 오늘 생긴 작은 마찰을 피하지 말고, 열린 마음으로 상대의 시각을 들여다보세요. 서로 다름을 이해하는 두 사람은 더 단단한 사랑을 만들어갑니다.', en: 'Minor disagreements with your partner are growth opportunities that deepen mutual understanding. Do not avoid the small friction that arises today—look into your partner\'s perspective with an open mind. Two people who understand each other\'s differences build a stronger love.', zh: '与恋人的小分歧是更深入理解关系的成长机会。今天不要回避出现的小摩擦，以开放的心态审视对方的视角。理解彼此差异的两个人会创造更坚固的爱情。', ja: '恋人との些細な意見の違いは関係をより深く理解する成長の機会です。今日生じた小さな摩擦を避けず、開かれた心で相手の視点を見てみてください。お互いの違いを理解する二人はより固い愛を作っていきます。', es: 'Los pequeños desacuerdos con tu pareja son oportunidades de crecimiento que profundizan la comprensión mutua. No evites la pequeña fricción que surge hoy—mira la perspectiva de tu pareja con mente abierta. Dos personas que entienden las diferencias del otro construyen un amor más fuerte.' },
      { ko: '자존심을 세우기보다 먼저 손을 내밀면 관계가 한층 부드럽고 따뜻해집니다. 누가 먼저 다가가는지는 중요하지 않으며, 두 사람이 함께 더 가까워진다는 것만이 의미 있습니다. 오늘 당신이 먼저 내미는 손이 상대의 마음 문을 열 열쇠가 될 것입니다.', en: 'Reaching out first rather than standing on pride makes the relationship warmer and softer. It does not matter who approaches first—what matters is only that the two of you grow closer together. The hand you extend first today will be the key that opens your partner\'s heart.', zh: '比起端架子，先伸出手，关系会更加柔和温暖。谁先靠近并不重要，重要的只是两个人一起变得更亲密。今天你先伸出的手，将成为打开对方心扉的钥匙。', ja: 'プライドを張るより先に手を差し伸べると関係がより穏やかで温かくなります。誰が先に近づくかは重要ではなく、二人が共によりリ近づくということだけが意味のあることです。今日あなたが先に差し伸べる手が相手の心の扉を開く鍵になるでしょう。', es: 'Extender la mano primero en lugar de mantener el orgullo hace la relación más cálida y suave. No importa quién se acerque primero—lo único que importa es que ustedes dos se acerquen más juntos. La mano que extiendes primero hoy será la llave que abre el corazón de tu pareja.' },
    ],
    low: [
      { ko: '자존심 때문에 사랑하는 사람과 멀어지고 있는 날입니다. 오늘의 양보는 지는 것이 아니라 더 소중한 것을 지키는 선택입니다. 오늘만큼은 내가 옳다는 증명보다 우리가 함께라는 사실을 선택하세요.', en: 'Pride is distancing you from your loved one today. Yielding today is not losing—it is the choice to protect something more precious. Today, choose the fact that you are together over proving that you are right.', zh: '今天自尊心正在让你与爱人疏远。今天的让步不是失败，而是保护更珍贵事物的选择。今天选择我们在一起这个事实，而不是证明自己是对的。', ja: 'プライドのせいで愛する人と離れつつある日です。今日の譲歩は負けではなく、より大切なものを守る選択です。今日だけは自分が正しいという証明より私たちが一緒だという事実を選んでください。', es: 'El orgullo te está alejando de tu ser amado hoy. Ceder hoy no es perder—es la elección de proteger algo más precioso. Hoy, elige el hecho de que están juntos sobre demostrar que tienes razón.' },
      { ko: '상대방의 관심이 부족하다고 느껴지더라도 성급한 판단은 금물인 날입니다. 사람은 누구나 자신만의 리듬과 공간이 필요하며, 그것이 사랑의 부재를 의미하지는 않습니다. 조금만 기다려보면 상대가 다시 당신에게 돌아올 것입니다.', en: 'Even if your partner\'s attention seems lacking today, rushing to judgment is forbidden. Everyone needs their own rhythm and space, and that does not mean an absence of love. Wait just a little longer and your partner will come back to you.', zh: '即使今天觉得对方关注不够，也绝不要急于判断。每个人都需要自己的节奏和空间，那并不意味着爱的缺失。再等一等，对方会回到你身边的。', ja: '相手の関心が足りないと感じても性急な判断は禁物な日です。人は誰でも自分なりのリズムと空間が必要で、それが愛の不在を意味するわけではありません。少し待てば相手はまたあなたのもとに戻ってきます。', es: 'Aunque la atención de tu pareja parezca escasa hoy, apresurarte a juzgar está prohibido. Todos necesitan su propio ritmo y espacio, y eso no significa una ausencia de amor. Espera un poco más y tu pareja volverá a ti.' },
      { ko: '감정을 격렬하게 표현하면 상대가 부담을 느끼는 날입니다. 사자자리의 열정은 아름답지만 오늘은 그 강도를 조금 낮추는 절제가 필요합니다. 조용하게 표현된 사랑이 때로는 폭발적인 표현보다 더 깊이 전달됩니다.', en: 'Expressing emotions intensely may overwhelm your partner today. Leo\'s passion is beautiful, but today some restraint to lower that intensity is needed. Love expressed quietly sometimes reaches deeper than love expressed explosively.', zh: '今天激烈地表达情感可能让对方感到负担。狮子座的热情是美丽的，但今天需要稍微降低强度的节制。安静表达的爱有时比爆发性的表达传达得更深。', ja: '感情を激しく表現すると相手が負担を感じる日です。獅子座の情熱は美しいですが今日はその強度を少し下げる節制が必要です。静かに表現された愛が時には爆発的な表現より深く伝わります。', es: 'Expresar emociones intensamente puede abrumar a tu pareja hoy. La pasión de Leo es hermosa, pero hoy se necesita algo de moderación para bajar esa intensidad. El amor expresado en silencio a veces llega más profundo que el amor expresado explosivamente.' },
      { ko: '질투심을 다스려야 하는 날입니다. 의심은 관계의 신뢰를 갉아먹는 가장 느린 독이며, 한번 퍼지면 되돌리기 어렵습니다. 오늘 질투가 느껴진다면 그것이 무엇에 대한 두려움인지를 먼저 들여다보세요.', en: 'Today you need to manage your jealousy. Suspicion is the slowest poison that erodes trust in a relationship, and once it spreads it is hard to reverse. If jealousy arises today, first look inside to find what fear lies behind it.', zh: '今天需要控制嫉妒心。怀疑是侵蚀关系信任最缓慢的毒药，一旦蔓延就很难逆转。今天如果感到嫉妒，先看看内心，找出背后是什么样的恐惧。', ja: '嫉妬心をコントロールしなければならない日です。疑いは関係の信頼を蝕む最も遅い毒であり、一度広がると取り戻すのが難しいです。今日嫉妬を感じたら、それが何に対する恐れなのかをまず見つめてみてください。', es: 'Hoy necesitas manejar tus celos. La sospecha es el veneno más lento que erosiona la confianza en una relación, y una vez que se extiende es difícil revertirla. Si surgen celos hoy, mira primero dentro para encontrar qué miedo yace detrás.' },
      { ko: '연인에게 왕처럼 대접받기를 강요하면 상대의 마음이 조용히 멀어집니다. 사랑은 권위가 아니라 따뜻함으로 유지되며, 오늘은 겸손하게 다가가는 것이 최선입니다. 당신이 낮아질 때 상대는 오히려 더 가까이 옵니다.', en: 'Demanding royal treatment from your partner quietly pushes their heart away. Love is sustained by warmth not authority, and today approaching with humility is best. When you lower yourself, your partner actually comes closer.', zh: '强迫恋人像对待国王一样会让对方的心悄悄疏远。爱靠温暖而非权威来维持，今天谦逊地靠近是最好的选择。当你放低姿态时，对方反而会更靠近。', ja: '恋人に王様のように扱われることを強要すると相手の心が静かに遠ざかります。愛は権威ではなく温かさで維持され、今日は謙虚に近づくことが最善です。あなたが低くなる時相手はかえってより近くに来ます。', es: 'Exigir trato real de tu pareja aleja silenciosamente su corazón. El amor se sostiene con calidez no con autoridad, y hoy acercarse con humildad es lo mejor. Cuando te bajas, tu pareja en realidad se acerca más.' },
      { ko: '오늘은 새로운 인연을 찾기보다 자신의 내면을 돌보는 시간이 더 필요합니다. 내면이 채워져 있을 때 비로소 좋은 사랑을 줄 수도 받을 수도 있습니다. 오늘 자신과 나누는 대화가 내일의 사랑을 더 건강하게 만들어 줄 것입니다.', en: 'Today you need time to care for your inner self more than to seek new connections. Only when you are filled within can you give and receive good love. The conversation you have with yourself today will make tomorrow\'s love healthier.', zh: '今天比起寻找新缘分，更需要照顾自己内心的时间。只有内心充实时，才能给予也能接受好的爱。今天与自己的对话，将让明天的爱更加健康。', ja: '今日は新しい縁を探すより自分の内面をケアする時間の方が必要です。内面が満たされている時こそ良い愛を与えることも受け取ることもできます。今日自分と交わす対話が明日の愛をより健全にしてくれるでしょう。', es: 'Hoy necesitas tiempo para cuidar tu interior más que para buscar nuevas conexiones. Solo cuando estás lleno por dentro puedes dar y recibir buen amor. La conversación que tengas contigo mismo hoy hará el amor de mañana más saludable.' },
      { ko: '과거의 연애 패턴을 돌아보면 같은 실수를 반복하고 있는지 보이는 날입니다. 우리는 익숙한 것을 반복하는 경향이 있지만, 그 패턴을 인식하는 것이 변화의 첫걸음입니다. 오늘 발견한 패턴 하나를 의식적으로 바꾸어보세요.', en: 'Looking back at your past relationship patterns today will reveal whether you are repeating the same mistakes. We all tend to repeat the familiar, but recognizing that pattern is the first step to change. Try consciously changing one pattern you discover today.', zh: '今天回顾过去的恋爱模式，就能看出是否在重复同样的错误。我们都倾向于重复熟悉的事，但认识到那个模式是改变的第一步。今天有意识地改变你发现的一个模式试试看。', ja: '過去の恋愛パターンを振り返ると同じ間違いを繰り返しているかどうかが見える日です。私たちは慣れ親しんだものを繰り返す傾向がありますが、そのパターンを認識することが変化の第一歩です。今日発見したパターン一つを意識的に変えてみてください。', es: 'Mirar hacia atrás en tus patrones de relaciones pasadas hoy revelará si estás repitiendo los mismos errores. Todos tendemos a repetir lo familiar, pero reconocer ese patrón es el primer paso para cambiar. Intenta cambiar conscientemente un patrón que descubras hoy.' },
      { ko: '감정적 폭발을 자제해야 하는 날입니다. 한번 뱉은 말은 주워 담을 수 없으며, 상처 입은 마음은 시간이 지나도 완전히 아물지 않기도 합니다. 오늘의 분노가 내일의 후회가 되지 않도록 숨을 고르세요.', en: 'Today you must restrain emotional outbursts. Words once spoken cannot be taken back, and a wounded heart sometimes never fully heals even with time. Take a breath so today\'s anger does not become tomorrow\'s regret.', zh: '今天需要克制情绪的爆发。说出的话收不回来，受伤的心有时即使过了时间也无法完全愈合。调整呼吸，不要让今天的愤怒成为明天的后悔。', ja: '感情的な爆発を自制しなければならない日です。一度吐いた言葉は取り戻せず、傷ついた心は時間が経っても完全に癒えないこともあります。今日の怒りが明日の後悔にならないよう呼吸を整えてください。', es: 'Hoy debes contener los estallidos emocionales. Las palabras dichas no se pueden retractar, y un corazón herido a veces nunca sana completamente incluso con el tiempo. Toma un respiro para que la ira de hoy no se convierta en el arrepentimiento de mañana.' },
      { ko: '사랑에서도 혼자 주도하려 하면 상대가 질식하는 날입니다. 사랑은 두 사람이 함께 만들어가는 공동 작품이지, 한 사람의 단독 공연이 아닙니다. 오늘은 손을 내밀어 상대와 함께 그 작품을 만들어보세요.', en: 'Trying to lead alone in love suffocates your partner today. Love is a collaborative work created by two people together, not a solo performance by one person. Today, extend your hand and create that work together with your partner.', zh: '今天在爱情中也试图独自主导会让对方窒息。爱是两个人共同创作的作品，不是一个人的独角戏。今天伸出手，与对方一起创造那件作品。', ja: '愛においても一人で主導しようとすると相手が窒息する日です。愛は二人が一緒に作り上げる共同作品であって、一人の独演ではありません。今日は手を差し伸べて相手と一緒にその作品を作ってみてください。', es: 'Tratar de liderar solo en el amor sofoca a tu pareja hoy. El amor es una obra colaborativa creada por dos personas juntas, no una actuación en solitario de una persona. Hoy, extiende tu mano y crea esa obra junto a tu pareja.' },
      { ko: '외로움을 잘못된 관계로 채우고 싶은 유혹이 있는 날입니다. 하지만 빈 공간을 잘못된 것으로 채우면 진짜를 위한 자리가 없어집니다. 혼자 서는 힘을 기르는 오늘이 내일 진정한 사랑을 맞이할 준비가 됩니다.', en: 'There is temptation to fill loneliness with wrong relationships today. But filling an empty space with the wrong thing leaves no room for the real thing. Building the strength to stand alone today prepares you to welcome true love tomorrow.', zh: '今天有用错误的关系填补孤独的诱惑。但用错误的东西填满空缺，就没有位置留给真正的了。今天培养独自站立的力量，就是在为明天迎接真正的爱情做准备。', ja: '外れを間違った関係で埋めたい誘惑がある日です。しかし空いた空間を間違ったもので埋めると本物のための場所がなくなります。一人で立つ力を育てる今日が明日真の愛を迎える準備になります。', es: 'Hoy hay tentación de llenar la soledad con relaciones equivocadas. Pero llenar un espacio vacío con lo incorrecto no deja lugar para lo verdadero. Construir la fuerza para estar solo hoy te prepara para dar la bienvenida al amor verdadero mañana.' },
    ],
  },
  career: {
    high: [
      { ko: '리더십이 빛을 발하는 날입니다. 당신이 방향을 제시할 때 팀이 하나로 모이는 것을 느낄 것입니다. 사자자리의 천부적인 리더십을 믿고 프로젝트를 성공으로 이끄세요.', en: 'Leadership shines today, and when you set the direction you will feel the team uniting as one. Trust Leo\'s innate leadership and drive the project to success—this is the moment your natural authority was meant for.', zh: '领导力闪耀的一天。当你指明方向时，你会感受到团队凝聚为一体。相信狮子座天赋的领导力，将项目引向成功——这正是你天然权威存在的时刻。', ja: 'リーダーシップが光を放つ日です。あなたが方向性を示すとチームが一つにまとまるのを感じるでしょう。獅子座の天賦のリーダーシップを信じてプロジェクトを成功に導いてください——これがあなたの天然の権威が存在する瞬間です。', es: 'El liderazgo brilla hoy, y cuando establezcas la dirección sentirás al equipo unirse como uno solo. Confía en el liderazgo innato de Leo y lleva el proyecto al éxito—este es el momento para el que fue hecha tu autoridad natural.' },
      { ko: '당신의 창의적 아이디어가 상사와 동료의 시선을 사로잡는 날입니다. 평소에 혼자 간직하고 있던 아이디어를 오늘 꺼내야 할 때입니다. 자신감을 가지고 발표하세요—당신의 관점이 팀 전체의 방향을 바꿀 수 있습니다.', en: 'Your creative ideas captivate bosses and colleagues today. This is the day to bring out the ideas you have been holding inside. Present with confidence—your perspective has the power to shift the entire team\'s direction.', zh: '今天你的创意想法吸引了上司和同事的目光。今天是拿出你一直独自珍藏的想法的时候了。自信地发表——你的观点有可能改变整个团队的方向。', ja: 'あなたの創造的なアイデアが上司と同僚の視線を捉える日です。普段一人で持っていたアイデアを今日出すべき時です。自信を持って発表してください——あなたの視点がチーム全体の方向性を変えることができます。', es: 'Tus ideas creativas cautivan a jefes y colegas hoy. Este es el día de sacar las ideas que has estado guardando para ti. Presenta con confianza—tu perspectiva tiene el poder de cambiar la dirección de todo el equipo.' },
      { ko: '중요한 프레젠테이션에서 태양 같은 존재감을 발휘하는 날입니다. 방에 들어서는 순간부터 모든 시선이 당신에게 집중될 것입니다. 무대를 장악하고, 당신이 준비해온 것을 세상에 보여줄 시간입니다.', en: 'You command sun-like presence in important presentations today. From the moment you enter the room, all eyes will be on you. Own the stage and show the world what you have prepared—the spotlight is yours.', zh: '今天在重要的演示中展现如太阳般的存在感。你一踏入房间，所有目光就会集中在你身上。掌控舞台，向世界展示你准备好的东西——聚光灯是你的。', ja: '重要なプレゼンテーションで太陽のような存在感を発揮する日です。部屋に入った瞬間から全ての視線があなたに集中するでしょう。ステージを掌握して、準備してきたものを世界に見せる時間です。', es: 'Demuestra presencia solar en presentaciones importantes hoy. Desde el momento en que entres a la sala, todos los ojos estarán en ti. Adueñate del escenario y muestra al mundo lo que has preparado—el reflector es tuyo.' },
      { ko: '승진이나 인정의 기회가 드디어 다가오는 날입니다. 오랫동안 쌓아온 노력이 드디어 빛을 발하는 시기가 왔습니다. 지금 이 순간을 망설임 없이 받아들이세요—당신은 이 인정을 받을 자격이 충분히 있습니다.', en: 'Opportunities for promotion or recognition finally approach today. The efforts you have accumulated over such a long time are finally about to shine. Accept this moment without hesitation—you have more than earned this recognition.', zh: '升职或认可的机会终于来临的一天。长期积累的努力终于要发光了。毫不犹豫地接受这一刻——你完全有资格获得这份认可。', ja: '昇進や認められるチャンスがついに近づいてくる日です。長い間積み上げてきた努力がついに光を放つ時期が来ました。この瞬間をためらわずに受け入れてください——あなたはこの認定を受けるに十分値します。', es: 'Las oportunidades de ascenso o reconocimiento finalmente se acercan hoy. Los esfuerzos que has acumulado durante tanto tiempo están a punto de brillar. Acepta este momento sin vacilación—te has ganado más que suficientemente este reconocimiento.' },
      { ko: '대담한 제안이 상대방을 설득하는 날입니다. 조심스럽게 숨겨두었던 아이디어를 오늘 과감하게 내놓으세요. 자신감이야말로 오늘 당신의 가장 강력한 무기임을 기억하세요.', en: 'Bold proposals persuade others today. Boldly bring out the idea you have been hiding cautiously. Remember that confidence is your most powerful weapon today.', zh: '大胆的提案说服对方的一天。果断地拿出你一直小心翼翼藏着的想法吧。记住，自信是你今天最强大的武器。', ja: '大胆な提案が相手を説得する日です。慎重に隠しておいたアイデアを今日果敢に出してください。自信こそが今日あなたの最も強力な武器であることを覚えておいてください。', es: 'Las propuestas audaces persuaden hoy. Saca con valentía la idea que has estado escondiendo cautelosamente. Recuerda que la confianza es tu arma más poderosa hoy.' },
      { ko: '새로운 프로젝트의 주도권을 잡기에 이보다 더 좋은 시기는 없습니다. 사자자리의 에너지가 충만한 지금이 바로 행동의 때입니다. 과감하게 나서세요—주도권을 잡는 자가 결과를 만듭니다.', en: 'There is no better time than this to take the lead on new projects. Now, when Leo\'s energy is at its fullest, is exactly the time for action. Step up boldly—those who seize the lead are the ones who shape the outcome.', zh: '掌握新项目主导权的最佳时机莫过于此。现在，当狮子座的能量最为充沛时，正是行动的时候。大胆地站出来——掌握主导权的人才能创造结果。', ja: '新しいプロジェクトの主導権を握るのにこれ以上良い時期はありません。獅子座のエネルギーが充満している今こそ行動の時です。果敢に前に出てください——主導権を握る者が結果を作ります。', es: 'No hay mejor momento que este para tomar el liderazgo de nuevos proyectos. Ahora, cuando la energía de Leo está en su punto más alto, es exactamente el momento para la acción. Da un paso al frente con valentía—quienes toman la iniciativa son los que dan forma al resultado.' },
      { ko: '당신의 열정이 팀 전체에 활력을 불어넣는 날입니다. 사자자리의 불꽃은 단순히 당신만 빛나게 하는 것이 아니라 주변 모두를 밝힙니다. 오늘 그 에너지를 아끼지 말고 나눠주세요—함께 최고의 성과를 만들어낼 수 있습니다.', en: 'Your passion energizes the entire team today. Leo\'s flame does not simply make you shine—it illuminates everyone around you. Share that energy freely today—together you can create the best results.', zh: '今天你的热情为整个团队注入活力。狮子座的火焰不只是让你一个人闪耀——它照亮了周围所有人。今天不要吝惜那股能量，尽情分享——大家一起可以创造最佳成果。', ja: 'あなたの情熱がチーム全体に活力を吹き込む日です。獅子座の炎は単にあなただけを輝かせるのではなく周り全員を照らします。今日そのエネルギーを惜しまず分け与えてください——一緒に最高の成果を作り出せます。', es: 'Tu pasión energiza a todo el equipo hoy. La llama de Leo no solo te hace brillar a ti—ilumina a todos a tu alrededor. Comparte esa energía libremente hoy—juntos pueden crear los mejores resultados.' },
      { ko: '중요한 계약이나 협상에서 유리한 결과를 얻는 날입니다. 사자자리의 당당한 자세와 설득력이 협상 테이블에서 빛납니다. 왕의 협상력을 발휘하세요—당신이 원하는 것을 요구하고, 그것을 얻으세요.', en: 'You achieve favorable outcomes in important contracts or negotiations today. Leo\'s confident posture and persuasiveness shine at the negotiating table. Show your royal negotiation skills—ask for what you want and get it.', zh: '今天在重要的合同或谈判中获得有利结果。狮子座自信的姿态和说服力在谈判桌上闪耀。发挥国王般的谈判力——要求你想要的，然后得到它。', ja: '重要な契約や交渉で有利な結果を得る日です。獅子座の堂々とした姿勢と説得力が交渉テーブルで輝きます。王の交渉力を発揮してください——望むものを要求してそれを手に入れてください。', es: 'Logras resultados favorables en contratos o negociaciones importantes hoy. La postura segura y la persuasión de Leo brillan en la mesa de negociaciones. Muestra tus habilidades de negociación real—pide lo que quieres y consíguelo.' },
      { ko: '오랫동안 구상했던 사업 아이디어를 실행에 옮기기에 더없이 좋은 날입니다. 생각하고 계획하는 단계는 이미 충분히 거쳤습니다. 이제는 행동할 시간이며, 오늘의 첫 발걸음이 당신의 꿈을 현실로 바꾸는 출발점이 됩니다.', en: 'Today is the finest possible day to put long-conceived business ideas into action. You have already spent more than enough time thinking and planning. Now is the time for action, and today\'s first step becomes the starting point that transforms your dream into reality.', zh: '今天是将长期构想的商业创意付诸实施的绝佳日子。思考和规划的阶段已经足够了。现在是行动的时候，今天迈出的第一步将成为把你的梦想变成现实的起点。', ja: '長い間構想してきた事業アイデアを実行に移すのにこれ以上ない良い日です。考えて計画する段階はすでに十分経ました。今は行動する時であり、今日の第一歩があなたの夢を現実に変える出発点になります。', es: 'Hoy es el mejor día posible para poner en acción ideas de negocio largamente concebidas. Ya has pasado más que suficiente tiempo pensando y planificando. Ahora es el momento para la acción, y el primer paso de hoy se convierte en el punto de partida que transforma tu sueño en realidad.' },
      { ko: '직장에서 당신의 진가가 드디어 인정받는 날입니다. 지금까지 묵묵히 최선을 다한 노력이 눈에 보이는 결과로 돌아오고 있습니다. 맡은 역할에 최선을 다하고, 이 인정을 자신감의 연료로 삼으세요.', en: 'Your true worth is finally recognized at work today. The efforts you have quietly given your best to are now returning as visible results. Do your best in your role and use this recognition as fuel for even greater confidence.', zh: '今天在职场你的真正价值终于得到认可。你一直默默全力以赴的努力正在以看得见的结果回报。在你的角色中尽全力，把这份认可作为自信的燃料。', ja: '職場であなたの真価がついに認められる日です。これまで黙々と最善を尽くしてきた努力が見える結果として返ってきています。任された役割に最善を尽くして、この認定を自信の燃料にしてください。', es: 'Tu verdadero valor finalmente es reconocido en el trabajo hoy. Los esfuerzos a los que has dado silenciosamente lo mejor de ti están regresando ahora como resultados visibles. Haz lo mejor en tu rol y usa este reconocimiento como combustible para una confianza aún mayor.' },
    ],
    medium: [
      { ko: '오늘은 리더보다 팀원의 역할에 충실하면 더 많은 것을 배울 수 있습니다. 사자자리의 강점은 이끄는 것만이 아니라, 언제 한 발 물러서야 할지 아는 지혜에도 있습니다. 오늘 동료들에게서 배우는 자세가 내일 더 강한 리더를 만들어줄 것입니다.', en: 'Today, fulfilling the role of a team member rather than a leader opens more doors for learning. Leo\'s true strength lies not only in leading but in knowing when to step back and absorb what others offer. The humility you practice today will forge a more powerful leader tomorrow.', zh: '今天做好团队成员的角色比当领导能学到更多。狮子座的真正力量不仅在于领导，也在于知道何时退后一步。今日的谦逊将塑造明日更强大的你。', ja: '今日はリーダーよりチームメンバーの役割に忠実であればもっと多くのことを学べます。獅子座の真の強みはリードするだけでなく、一歩引くべき時を知る知恵にもあります。今日の謙虚さが明日より強いリーダーを育てます。', es: 'Hoy, ser un miembro fiel del equipo en lugar de líder abre más puertas de aprendizaje. La humildad que practicas hoy forjará un líder más poderoso mañana.' },
      { ko: '인정받고 싶은 마음을 내려놓고 묵묵히 실력을 쌓는 것이 현명합니다. 사자자리는 빛을 원하지만, 오늘은 그 빛을 내면의 성장으로 향하게 할 기회입니다. 오늘 쌓은 실력은 언젠가 당신이 원하는 무대에서 가장 찬란하게 빛날 것입니다.', en: 'Letting go of the desire for recognition and quietly building skills is the wisest move today. Leo naturally seeks the spotlight, but today\'s opportunity is to direct that energy inward toward genuine growth. The skills you build now will shine most brilliantly when your true stage arrives.', zh: '放下想被认可的心，默默积累实力是明智的。狮子座渴望光芒，但今天是将那光芒引向内在成长的机会。你今日积累的实力，终将在属于你的舞台上最耀眼地绽放。', ja: '認められたい気持ちを手放し黙々と実力を積むのが賢明です。獅子座は輝きを求めますが、今日はその光を内なる成長に向ける機会です。今日積んだ実力はいつかあなたが望む舞台で最も輝きます。', es: 'Soltar el deseo de reconocimiento y construir habilidades en silencio es lo más sabio hoy. Las habilidades que desarrollas ahora brillarán con más fuerza cuando llegue tu verdadero escenario.' },
      { ko: '동료의 의견에 열린 마음으로 귀 기울이면 예상치 못한 해결책이 보입니다. 카리스마 넘치는 사자자리도 혼자 보지 못하는 각도가 있습니다. 오늘은 경청 자체가 당신의 가장 강력한 리더십 도구임을 기억하세요.', en: 'Listening to colleagues with an open mind today reveals unexpected solutions you couldn\'t have found alone. Even the most charismatic Leo has blind spots that others can illuminate. Remember that today, active listening is your most powerful leadership tool.', zh: '以开放的心态倾听同事的意见会发现意想不到的解决方案。即使是最有魅力的狮子座，也有别人能照亮的盲点。记住，今天主动倾听就是你最强大的领导力工具。', ja: '同僚の意見に開かれた心で耳を傾ければ予想外の解決策が見えてきます。カリスマあふれる獅子座でも一人では見えない角度があります。今日は傾聴こそがあなたの最も強力なリーダーシップツールであることを覚えておいてください。', es: 'Escuchar a colegas con mente abierta hoy revela soluciones inesperadas que no podrías encontrar solo. Recuerda que hoy, escuchar activamente es tu herramienta de liderazgo más poderosa.' },
      { ko: '자신만의 속도로 착실하게 진행하세요. 서두르면 품질이 떨어질 수 있으며, 그것은 사자자리의 왕다운 이미지와도 맞지 않습니다. 오늘은 빠른 완성보다 완성도 높은 결과물이 더 강한 인상을 남깁니다.', en: 'Proceed steadily at your own pace today, as rushing may lower quality in ways that don\'t suit Leo\'s regal standards. The hidden opportunity lies in the deliberate pace—a polished result leaves a far stronger impression than a rushed one. Choose depth over speed today.', zh: '按自己的速度踏实地进行。急躁可能降低质量，这与狮子座的王者形象不符。今天，高完成度的成果比快速完成更能留下深刻印象。', ja: '自分のペースで着実に進めてください。焦ると品質が落ちることがあり、それは獅子座の王らしいイメージにも合いません。今日は速い完成より完成度の高い成果物がより強い印象を残します。', es: 'Avanza de manera constante a tu propio ritmo, ya que apresurarte puede reducir la calidad. Un resultado pulido deja una impresión mucho más fuerte que uno apresurado—elige profundidad sobre velocidad hoy.' },
      { ko: '화려한 성과보다 꼼꼼한 디테일이 중요한 날입니다. 기본기를 다지세요.', en: 'Careful details matter more than flashy results today. Strengthen your fundamentals.', zh: '比起华丽的成果，细致的细节更重要的一天。夯实基础。', ja: '華やかな成果よりきめ細かいディテールが重要な日です。基本を固めてください。', es: 'Los detalles cuidadosos importan más que resultados llamativos hoy. Fortalece tus fundamentos.' },
      { ko: '비판을 개인적 공격으로 받아들이지 마세요. 성장의 피드백으로 활용하세요.', en: 'Don\'t take criticism as personal attacks. Use it as growth feedback.', zh: '不要把批评当成人身攻击。作为成长的反馈来利用。', ja: '批判を個人的な攻撃と受け取らないでください。成長のフィードバックとして活用してください。', es: 'No tomes las críticas como ataques personales. Úsalas como retroalimentación para crecer.' },
      { ko: '업무 우선순위를 재정립하세요. 모든 일을 동시에 잘할 수는 없으며, 분산된 에너지는 사자자리의 강렬한 집중력을 약하게 만듭니다. 오늘 가장 중요한 한 가지에 당신의 전부를 쏟아부어 보세요.', en: 'Reestablish work priorities today, as you can\'t excel at everything simultaneously and scattered energy dilutes Leo\'s intense focus. The hidden opportunity is in the radical act of choosing—when you pour your full energy into one thing, the results become extraordinary. Pick your most important task and give it everything.', zh: '重新确立工作优先级。不可能同时做好所有事，分散的精力会削弱狮子座强烈的专注力。今天，把你的全部投入最重要的一件事上。', ja: '業務の優先順位を再設定してください。全てのことを同時にうまくやることはできず、分散したエネルギーは獅子座の強烈な集中力を弱めます。今日最も重要な一つのことにあなたの全てを注いでみてください。', es: 'Restablece las prioridades laborales hoy, ya que no puedes sobresalir en todo a la vez. Cuando viertes toda tu energía en una cosa, los resultados se vuelven extraordinarios—elige tu tarea más importante y dalo todo.' },
      { ko: '경쟁심을 내려놓고 협력에 집중하면 더 큰 성과가 따릅니다. 사자자리는 혼자 빛날 때도 아름답지만, 함께 이룬 승리에서 진정한 왕의 위엄이 드러납니다. 오늘 한 명의 동료를 도와주는 작은 행동이 팀 전체를 움직이는 전환점이 될 것입니다.', en: 'Letting go of competitiveness and focusing on cooperation brings far greater results today. Leo shines brilliantly alone, but true royal dignity emerges in victories achieved together. Take one small action to support a colleague today—it could become the turning point that moves the entire team forward.', zh: '放下竞争心，专注于合作会带来更大的成果。狮子座独自闪耀时固然美丽，但共同赢得的胜利才能展现真正的王者威严。今天帮助一位同事的小小举动，将成为推动整个团队前进的转折点。', ja: '競争心を手放し協力に集中するとより大きな成果が伴います。獅子座は一人で輝く時も美しいですが、共に成し遂げた勝利に真の王の威厳が現れます。今日一人の同僚を助ける小さな行動がチーム全体を動かす転換点になるでしょう。', es: 'Soltar la competitividad y enfocarse en la cooperación trae resultados mucho mayores hoy. Toma una pequeña acción para apoyar a un colega—podría convertirse en el punto de inflexión que impulse a todo el equipo.' },
      { ko: '단기 성과보다 장기적 커리어 비전에 맞춰 오늘의 업무를 선택하세요.', en: 'Choose today\'s tasks aligned with long-term career vision rather than short-term results.', zh: '比起短期成果，根据长期职业愿景选择今天的工作。', ja: '短期的な成果より長期的なキャリアビジョンに合わせて今日の業務を選んでください。', es: 'Elige las tareas de hoy alineadas con tu visión profesional a largo plazo en vez de resultados a corto plazo.' },
      { ko: '완벽한 결과를 기대하기보다 꾸준한 노력의 과정을 신뢰하세요. 오늘의 작은 진전이 내일의 커다란 도약을 만드는 법이며, 사자자리의 위대함은 한 번의 폭발이 아닌 지속적인 존재감에서 나옵니다. 오늘도 자신을 위해 한 걸음 나아가는 것—그것으로 충분합니다.', en: 'Trust the process of consistent effort rather than expecting perfect results today. Leo\'s greatness doesn\'t come from a single explosion but from a sustained, powerful presence over time. Today\'s small step forward is enough—keep showing up for yourself, and the results will follow.', zh: '比起期待完美的结果，信任持续努力的过程。狮子座的伟大不来自一次爆发，而来自持续而强大的存在感。今天继续为自己迈出一步——这就足够了，结果自然会随之而来。', ja: '完璧な結果を期待するよりコツコツとした努力の過程を信頼してください。獅子座の偉大さは一度の爆発ではなく持続的で強力な存在感から生まれます。今日も自分のために一歩進むこと——それで十分です。', es: 'Confía en el proceso del esfuerzo constante en lugar de esperar resultados perfectos hoy. La grandeza de Leo no viene de una sola explosión, sino de una presencia sostenida y poderosa. El pequeño paso de hoy es suficiente—sigue avanzando.' },
    ],
    low: [
      { ko: '직장에서 자존심 충돌이 생길 수 있습니다. 이런 긴장감은 사자자리처럼 강한 존재감을 가진 사람에게는 자연스러운 일이며, 당신만의 문제가 아닙니다. 오늘은 감정을 절제하고 프로답게 대처하는 것이 진정한 왕의 품격을 보여주는 방법입니다.', en: 'Pride clashes may occur at work today, and it helps to know this tension is natural when you carry Leo\'s powerful presence—it\'s not a personal failure. The protective wisdom here is that how you respond, not what triggered you, is what defines your reputation. Restrain your emotions and handle things professionally—that is true royal dignity.', zh: '职场可能发生自尊心冲突。这种紧张感对拥有强烈存在感的狮子座来说是自然的，并非只是你的问题。今天克制情绪、以专业态度应对，才是展现真正王者风范的方式。', ja: '職場でプライドの衝突が起きるかもしれません。この緊張感は強い存在感を持つ獅子座には自然なことで、あなただけの問題ではありません。今日は感情を節制しプロらしく対処することが真の王の品格を示す方法です。', es: 'Pueden ocurrir choques de orgullo en el trabajo hoy, y debes saber que esta tensión es natural para alguien con la poderosa presencia de Leo. Controla las emociones y actúa profesionalmente—esa es la verdadera dignidad real.' },
      { ko: '성급한 결정은 큰 손실로 이어질 수 있습니다. 행동력이 강한 사자자리에게 기다림은 고통스러울 수 있지만, 지금의 인내가 훗날의 더 큰 승리를 보장해줍니다. 충분히 검토한 후 실행하세요—그것이 오늘 당신에게 필요한 진정한 용기입니다.', en: 'Hasty decisions may lead to significant losses today—and for action-driven Leo, waiting can feel painful. But the protective wisdom is clear: the patience you practice now guarantees a much greater victory later. Execute only after thorough review—that is the true courage you need today.', zh: '仓促的决定可能导致大损失。对于行动力强的狮子座，等待可能令人痛苦，但现在的耐心保证了日后更大的胜利。充分审查后再执行——这才是今天你需要的真正勇气。', ja: '性急な決定は大きな損失につながりかねません。行動力の強い獅子座には待つことが辛いかもしれませんが、今の忍耐が後のより大きな勝利を保証します。十分に検討した後に実行してください——それが今日あなたに必要な真の勇気です。', es: 'Las decisiones apresuradas pueden llevar a grandes pérdidas hoy. La paciencia que practicas ahora garantiza una victoria mucho mayor después. Ejecuta solo después de una revisión exhaustiva—ese es el verdadero coraje que necesitas.' },
      { ko: '혼자 모든 공을 차지하려 하면 팀의 신뢰를 잃습니다. 왕은 혼자 빛나는 것이 아니라 주변을 빛나게 함으로써 더욱 위대해진다는 것을 기억하세요. 오늘 공로를 나누는 한 마디가 당신의 리더십에 대한 가장 강력한 신뢰를 만들어줄 것입니다.', en: 'Trying to take all the credit alone risks losing the team\'s trust—a significant setback for Leo\'s leadership aspirations. Remember that a true king becomes greater by making those around them shine, not by hoarding the light. Sharing credit today creates the most powerful endorsement of your leadership.', zh: '试图独占所有功劳会失去团队的信任。记住，真正的王者不是独自发光，而是让周围的人也闪耀，从而变得更伟大。今天分享功劳的一句话，将为你的领导力创造最有力的信任。', ja: '一人で全ての手柄を独り占めしようとするとチームの信頼を失います。真の王は一人で輝くのではなく、周りを輝かせることでより偉大になることを覚えておいてください。今日功績を分かち合う一言があなたのリーダーシップへの最も強い信頼を生みます。', es: 'Intentar tomar todo el crédito solo arriesga la confianza del equipo. Un verdadero rey se vuelve más grande haciendo que los que le rodean brillen. Compartir el mérito hoy crea el respaldo más poderoso para tu liderazgo.' },
      { ko: '무리한 목표 설정은 번아웃을 초래합니다. 사자자리의 야망은 아름답지만, 지금은 불꽃을 아껴 더 오래 타오르게 할 지혜가 필요한 시기입니다. 현실적인 계획을 세우는 것—그것이 오늘 당신의 에너지를 지키는 가장 용감한 선택입니다.', en: 'Unrealistic goal-setting leads to burnout, and Leo\'s soaring ambitions need wise management right now. The protective wisdom is that guarding your flame so it burns longer is not retreat—it is strategy. Making realistic plans today is the bravest choice you can make for your future self.', zh: '过高的目标设定导致倦怠。狮子座的雄心壮志是美丽的，但现在是需要节约火焰、让它燃烧更久的智慧时期。制定现实的计划——这是今天守护你能量最勇敢的选择。', ja: '無理な目標設定はバーンアウトを招きます。獅子座の野望は美しいですが、今は炎を大切にしてより長く燃え続けさせる知恵が必要な時期です。現実的な計画を立てること——それが今日あなたのエネルギーを守る最も勇敢な選択です。', es: 'Establecer metas poco realistas lleva al agotamiento. Guardar tu llama para que arda más tiempo no es retroceder—es estrategia. Hacer planes realistas hoy es la elección más valiente para tu yo futuro.' },
      { ko: '상사나 클라이언트의 부정적 피드백에 과민하게 반응하지 마세요. 비판은 당신의 가치를 부정하는 것이 아니라, 더 나은 결과를 위한 정보일 뿐입니다. 한 발짝 물러나 냉정하게 들을 수 있다면, 그 피드백 안에 숨어 있는 기회를 발견하게 될 것입니다.', en: 'Don\'t overreact to negative feedback from bosses or clients today—it is information about the work, not a verdict on your worth as Leo. Taking one step back to listen calmly is protective wisdom that prevents impulsive damage. Inside that feedback, there is often a hidden opportunity waiting to be discovered.', zh: '不要对上司或客户的负面反馈过度反应。批评不是在否定你的价值，只是为了更好结果的信息。如果能退一步冷静地聆听，你将在那份反馈中发现隐藏的机会。', ja: '上司やクライアントの否定的なフィードバックに過敏に反応しないでください。批判はあなたの価値を否定するのではなく、より良い結果のための情報に過ぎません。一歩引いて冷静に聞けるなら、そのフィードバックの中に隠れた機会を見つけることができます。', es: 'No reacciones exageradamente a comentarios negativos hoy—es información sobre el trabajo, no un veredicto sobre tu valor. Dar un paso atrás para escuchar con calma revela la oportunidad oculta dentro de esa retroalimentación.' },
      { ko: '업무에서 고집을 부리면 기회를 놓칩니다. 사자자리의 강한 신념은 큰 자산이지만, 오늘은 그 신념을 잠시 옆에 두고 다른 관점을 탐색해볼 때입니다. 유연한 사고는 약함이 아니라, 더 강한 왕이 되는 과정입니다.', en: 'Stubbornness at work today risks closing the door on unexpected opportunities. Leo\'s strong convictions are a great asset, but today calls for setting them aside temporarily to explore different angles. Flexible thinking is not weakness—it is the mark of a king who keeps growing stronger.', zh: '在工作中固执会错过机会。狮子座强烈的信念是巨大的资产，但今天是暂时放下信念、探索不同视角的时候。灵活的思维不是软弱，而是成为更强王者的过程。', ja: '業務で頑固になるとチャンスを逃します。獅子座の強い信念は大きな資産ですが、今日はその信念を一旦脇に置いて別の視点を探求する時です。柔軟な思考は弱さではなく、より強い王になる過程です。', es: 'La terquedad en el trabajo hoy cierra puertas a oportunidades inesperadas. Las fuertes convicciones de Leo son un gran activo, pero hoy llama a explorar diferentes ángulos. El pensamiento flexible no es debilidad—es la marca de un rey que sigue creciendo.' },
      { ko: '오늘은 중요한 계약이나 협상을 미루는 것이 현명합니다. 최고의 타이밍을 기다리는 것은 포기가 아니라, 가장 유리한 순간에 당신의 힘을 집중시키는 전략입니다. 지금 한 발 물러서는 것이 내일 더 강한 협상력을 만들어줄 것입니다.', en: 'It\'s wise to postpone important contracts or negotiations today, as the timing is simply not in your favor. Waiting for the right moment is not giving up—it is the strategy of concentrating your Leo force at the most advantageous instant. Stepping back now will give you far stronger negotiating power tomorrow.', zh: '今天推迟重要的合同或谈判是明智的。等待最佳时机不是放弃，而是在最有利时刻集中你力量的策略。现在退一步将为明天带来更强的谈判力。', ja: '今日は重要な契約や交渉を延期するのが賢明です。最高のタイミングを待つことは諦めではなく、最も有利な瞬間にあなたの力を集中させる戦略です。今一歩引くことが明日より強い交渉力を生みます。', es: 'Es sabio posponer contratos o negociaciones importantes hoy. Esperar el momento adecuado no es rendirse—es la estrategia de concentrar la fuerza de Leo en el instante más ventajoso. Dar un paso atrás ahora te dará un poder de negociación mucho mayor mañana.' },
      { ko: '주도권을 잡으려는 과도한 시도가 갈등을 불러올 수 있습니다. 통제 욕구는 불안감에서 비롯될 때가 많은데, 오늘은 그 불안을 인정하고 잠시 쉬어가도 괜찮습니다. 진정한 리더는 모든 것을 통제하는 사람이 아니라, 사람들이 자발적으로 따르고 싶게 만드는 사람입니다.', en: 'Excessive attempts to take control today may trigger conflict you didn\'t intend to create. The urge to control often comes from underlying anxiety—it\'s okay to acknowledge that and give yourself a moment to breathe. A true leader is not someone who controls everything, but someone others genuinely want to follow. Focus on coordination today.', zh: '过度试图掌握主导权可能引发冲突。控制欲往往源于不安感，今天承认这种不安、稍作休息也是可以的。真正的领导者不是控制一切的人，而是让人自愿追随的人。致力于协调。', ja: '主導権を握ろうとする過度な試みが対立を招くことがあります。支配したい衝動は不安感から来ることが多く、今日はその不安を認めて少し休んでも大丈夫です。真のリーダーとは全てをコントロールする人ではなく、人々が自ら従いたいと思わせる人です。調整に努めてください。', es: 'Intentos excesivos de tomar el control hoy pueden desencadenar conflictos no deseados. El impulso de controlar a menudo viene de la ansiedad—está bien reconocerlo y darte un momento para respirar. Un verdadero líder no controla todo, sino que hace que otros quieran seguirle voluntariamente.' },
      { ko: '조급하게 성과를 보여주려 하면 실수가 생깁니다. 빛나고 싶은 마음은 사자자리의 본능이지만, 지금 이 순간의 조급함이 당신이 쌓아온 모든 것을 흔들 수 있습니다. 오늘은 신중하게 진행하세요—내일의 더 완벽한 무대를 위해 오늘을 준비하는 것입니다.', en: 'Rushing to show results leads to mistakes today, and Leo\'s natural desire to shine can inadvertently undermine everything you\'ve built. The struggle to be patient is real and valid, but the work you do carefully now is preparing a more perfect stage for tomorrow. Proceed with deliberate care—your moment is coming.', zh: '急于展示成果会出现失误。想要闪耀是狮子座的本能，但此刻的急躁可能动摇你积累的一切。今天谨慎地进行——这是在为明天更完美的舞台做准备。', ja: '焦って成果を見せようとするとミスが生じます。輝きたい気持ちは獅子座の本能ですが、今この瞬間の焦りがあなたが積み上げてきた全てを揺るがす可能性があります。今日は慎重に進めてください——明日のより完璧な舞台のために今日を準備しているのです。', es: 'Apresurarse a mostrar resultados lleva a errores hoy. El deseo natural de Leo de brillar puede socavar inadvertidamente todo lo que has construido. Procede con cuidado deliberado—tu momento se acerca y la paciencia de hoy lo hace más perfecto.' },
      { ko: '체면 때문에 모르는 것을 아는 척하지 마세요. 모르는 것을 인정하기 어렵다는 느낌은 누구나 갖는 것이며, 특히 리더십을 중시하는 사자자리에게는 더욱 그렇습니다. 하지만 진심 어린 질문 하나가 당신의 위신을 깎는 것이 아니라, 오히려 지성과 성장에 대한 의지를 보여주는 가장 강력한 신호입니다.', en: 'Don\'t pretend to know what you don\'t just for appearances—the struggle to admit gaps in knowledge is universal, and especially real for Leo who values leadership. But a genuine question doesn\'t diminish your standing; it signals intelligence and willingness to grow, which are the most compelling leadership qualities. Asking questions today is your true courage.', zh: '不要因为面子假装知道不懂的事。承认不知道的感觉对每个人都很难，对重视领导力的狮子座尤其如此。但一个真诚的问题不会降低你的威信，反而是展示智慧和成长意愿最有力的信号。', ja: '体面のために知らないことを知ったふりしないでください。知識の不足を認めることの難しさは誰もが感じるものであり、特にリーダーシップを重んじる獅子座には一層リアルです。しかし真摯な質問はあなたの威信を下げるのではなく、むしろ知性と成長への意欲を示す最も力強いシグナルです。', es: 'No finjas saber lo que no sabes por las apariencias—la lucha por admitir vacíos en el conocimiento es universal, especialmente para Leo que valora el liderazgo. Pero una pregunta genuina no disminuye tu estatura; señala inteligencia y voluntad de crecer. Hacer preguntas hoy es tu verdadero coraje.' },
    ],
  },
  health: {
    high: [
      { ko: '태양 에너지가 가득한 날입니다. 몸과 마음 모두 활력이 넘치며, 사자자리를 지배하는 태양의 힘이 오늘 당신의 세포 하나하나에 생기를 불어넣고 있습니다. 이 황금빛 에너지를 온전히 받아들이고, 원하는 모든 것에 과감하게 도전해보세요.', en: 'A day full of solar energy, with both body and mind overflowing with vitality unique to Leo\'s solar ruler. Every cell in you is charged with golden life force today—you can feel it in the lightness of your step and the clarity of your mind. Open yourself fully to this energy and boldly pursue anything you desire.', zh: '充满太阳能量的一天。身心都充满活力，太阳——狮子座的守护星——今天将生机注入你的每一个细胞。完全接受这金色能量，勇敢地向一切你想要的事物发起挑战。', ja: '太陽エネルギーが満ちた日です。体も心も活力にあふれ、獅子座を支配する太陽の力が今日あなたの細胞一つひとつに生気を吹き込んでいます。この黄金のエネルギーを全て受け取り、望むものすべてに果敢に挑戦してみてください。', es: 'Un día lleno de energía solar, con cuerpo y mente desbordando vitalidad única de Leo. Cada célula en ti está cargada con fuerza vital dorada hoy. Ábrete completamente a esta energía y persigue audazmente todo lo que deseas.' },
      { ko: '운동을 시작하거나 새로운 건강 루틴을 만들기에 완벽한 날입니다. 오늘의 높은 에너지가 새로운 습관을 형성하는 데 가장 강력한 연료가 되어줄 것입니다. 지금 이 순간의 결심이 30일 후 당신의 몸과 마음을 완전히 변화시키는 첫 번째 발걸음입니다.', en: 'This is a perfect day to start exercising or create a new health routine, with today\'s elevated Leo energy providing the strongest fuel for forming new habits. The decision you make right now is the first step that will completely transform your body and mind in thirty days. Don\'t wait—start today and feel the momentum build.', zh: '这是开始运动或建立新健康习惯的完美一天。今天高涨的能量将成为养成新习惯最强大的燃料。此刻的决心是30天后彻底改变你身心的第一步——立即行动。', ja: '運動を始めたり新しい健康ルーティンを作るのに完璧な日です。今日の高まったエネルギーが新しい習慣を形成する最も強力な燃料になります。今この瞬間の決意が30日後あなたの体と心を完全に変える第一歩です。', es: 'Este es un día perfecto para comenzar a ejercitarte o crear una nueva rutina de salud. La energía elevada de hoy proporciona el combustible más poderoso para formar nuevos hábitos. La decisión que tomas ahora es el primer paso que transformará tu cuerpo en treinta días.' },
      { ko: '심장과 혈관이 활기차게 뛰고 있습니다. 사자자리는 태양에 지배받는 만큼 심장 건강이 활력의 원천인데, 오늘은 그 엔진이 최고 출력으로 가동되는 날입니다. 유산소 운동으로 이 황금빛 에너지를 증폭시켜 온몸에 퍼뜨려보세요.', en: 'Heart and blood vessels pump vigorously today—and for Leo, ruled by the sun, the heart is truly the engine of all vitality. Today that engine is running at peak power, ready to be amplified. Embrace aerobic exercise to spread this golden energy through your entire body and feel unstoppable.', zh: '心脏和血管充满活力地跳动。狮子座受太阳支配，心脏是活力的源泉，而今天这台引擎在最高功率运转。用有氧运动放大这股金色能量，让它遍布全身。', ja: '心臓と血管が活気よく動いています。獅子座は太陽に支配されるように心臓が活力の源ですが、今日はそのエンジンが最高出力で動いている日です。有酸素運動でこの黄金のエネルギーを増幅させ全身に広げてください。', es: 'El corazón y los vasos sanguíneos laten vigorosamente hoy. Para Leo, regido por el sol, el corazón es el motor de toda vitalidad, y hoy ese motor funciona a máxima potencia. Amplifica esta energía dorada con ejercicio aeróbico y siéntete imparable.' },
      { ko: '내면의 불꽃이 면역력을 높여줍니다. 사자자리의 강렬한 생명에너지가 오늘 바이러스와 피로를 막아내는 보호막처럼 작동하고 있습니다. 오늘을 활동적으로 보내면서 이 불꽃을 더욱 세차게 타오르게 만드세요.', en: 'The inner flame of Leo boosts immunity today, with your intense life energy working like a protective shield against viruses and fatigue. This powerful force is at its height right now, ready to be channeled. Spend today actively and fan that flame even brighter—your body is your greatest asset.', zh: '内在的火焰提升免疫力。狮子座强烈的生命能量今天像防御病毒和疲劳的保护盾一样运作。积极活动今天，让这火焰燃烧得更旺盛。', ja: '内なる炎が免疫力を高めてくれます。獅子座の強烈な生命エネルギーが今日ウイルスや疲労を防ぐ保護膜のように働いています。今日を活動的に過ごしてこの炎をより激しく燃え上がらせてください。', es: 'La llama interior de Leo fortalece la inmunidad hoy, con tu intensa energía vital funcionando como un escudo protector. Pasa hoy de forma activa y aviva esa llama aún más brillante—tu cuerpo es tu mayor activo.' },
      { ko: '스트레스가 한꺼번에 해소되는 느낌입니다. 쌓였던 긴장이 녹아내리며 몸과 마음이 본연의 가벼움을 되찾는 날입니다. 자연 속에서 에너지를 충전하면, 태양 아래 사자처럼 다시 당당하고 자유로운 자신을 만날 것입니다.', en: 'Stress feels like it dissolves all at once today, with accumulated tension melting away as body and mind reclaim their natural lightness. This relief is real and you deserve to feel it fully. Recharge your energy in nature—like a lion basking freely under the sun, you\'ll rediscover your most powerful, authentic self.', zh: '感觉压力一下子消解了。积累的紧张正在融化，身心重拾本来的轻盈。在大自然中充电，像在太阳下自由沐浴的狮子，你将重新遇见最强大、最真实的自己。', ja: 'ストレスが一気に解消される感じです。溜まっていた緊張が溶けていき体と心が本来の軽さを取り戻す日です。自然の中でエネルギーを充電すれば、太陽の下で自由に過ごすライオンのように、再び堂々と自由な自分に出会うでしょう。', es: 'El estrés se disuelve de golpe hoy, con la tensión acumulada derritiéndose mientras cuerpo y mente recuperan su ligereza natural. Recarga tu energía en la naturaleza—como un león bañándose libremente bajo el sol, redescubrirás tu yo más poderoso y auténtico.' },
      { ko: '체력이 정점에 달합니다. 평소엔 두려워서 시작하지 못했던 운동이나 신체 도전이 있다면, 오늘이 바로 그 벽을 넘어설 완벽한 날입니다. 사자자리의 용기와 극대화된 체력이 만나는 지금, 당신은 스스로도 놀랄 만한 결과를 만들어낼 것입니다.', en: 'Physical strength peaks today in a way that is unmistakably felt—you are ready for anything. If there\'s an exercise or physical challenge you\'ve been too afraid to start, today is the perfect day to break through that wall. With Leo\'s natural courage meeting this peak stamina, you will create results that surprise even yourself.', zh: '体力达到顶点。如果有平时因为害怕而无法开始的运动或身体挑战，今天正是突破那道墙的完美时机。狮子座的勇气与极致体力相遇的此刻，你将创造连自己都惊叹的成果。', ja: '体力が頂点に達します。普段は怖くて始められなかった運動や身体的な挑戦があるなら、今日がその壁を越える完璧な日です。獅子座の勇気と最大化された体力が出会う今、自分でも驚くほどの結果を生み出せるでしょう。', es: 'La fuerza física alcanza su punto máximo hoy. Si hay un ejercicio o desafío físico que has tenido miedo de comenzar, hoy es el día perfecto para romper esa barrera. Con el coraje de Leo encontrando esta resistencia máxima, crearás resultados que te sorprenderán incluso a ti.' },
      { ko: '양질의 수면과 함께 개운한 아침이 시작됩니다. 잠에서 깨는 순간부터 당신의 몸이 충분히 회복되었음을 느낄 것이며, 이 가벼움이 오늘 하루의 모든 행동에 황금빛 힘을 실어줍니다. 이 에너지를 당신이 사랑하는 것들에 쏟아부으세요.', en: 'A refreshing morning begins with the gift of quality sleep, and from the moment you wake you will feel your body fully restored. This lightness you carry will infuse golden power into every action you take today. Pour this remarkable energy into the people and things you love most.', zh: '伴随高质量睡眠，清爽的早晨开始。从醒来的瞬间，你就能感受到身体完全恢复，这种轻盈感为今天的每个行动注入金色力量。将这能量倾注到你最爱的事物上。', ja: '良質な睡眠と共に爽やかな朝が始まります。目覚めた瞬間から体が十分に回復していることを感じ、この軽やかさが今日一日の全ての行動に黄金の力を実らせます。このエネルギーをあなたが愛するものに注いでください。', es: 'Una mañana refrescante comienza con el regalo de sueño de calidad, y desde el momento en que despiertas sentirás tu cuerpo completamente restaurado. Esta ligereza infundirá poder dorado en cada acción que realices hoy. Vierte esta energía notable en las personas y cosas que más amas.' },
      { ko: '오늘의 건강 에너지를 이용해 나쁜 습관을 끊기 시작하면 효과가 큽니다. 사자자리의 강한 의지력이 오늘 최고조에 달해 있어, 평소라면 어렵게 느껴지던 변화가 오늘만큼은 자연스럽게 흘러갑니다. 오래 미뤄왔던 변화를 지금 시작하세요—오늘의 결단이 새로운 당신의 시작점입니다.', en: 'Using today\'s exceptional health energy to start breaking bad habits will have remarkable effects, as Leo\'s powerful will reaches its peak right now. Changes that normally feel difficult will flow naturally today—your motivation and capacity align in a rare and powerful way. Begin the transformation you\'ve been postponing. Today is the turning point.', zh: '利用今天卓越的健康能量开始戒掉坏习惯效果巨大。狮子座强大的意志力今天达到顶峰，平时感觉困难的改变今天将自然流动。开始你一直推迟的改变——今天的决断是新的你的起点。', ja: '今日の健康エネルギーを利用して悪い習慣を断ち始めれば効果が大きいです。獅子座の強い意志力が今日最高潮に達しており、普段なら難しく感じる変化が今日だけは自然に流れます。ずっと先延ばしにしてきた変化を今始めてください——今日の決断が新しいあなたの出発点です。', es: 'Usar la excepcional energía de salud de hoy para romper malos hábitos tendrá efectos notables, ya que la poderosa voluntad de Leo alcanza su punto máximo ahora. Los cambios que normalmente se sienten difíciles fluirán naturalmente hoy. Comienza la transformación que has pospuesto—hoy es el punto de inflexión.' },
      { ko: '사자자리 특유의 생명력이 가득합니다. 당신이 방에 들어서는 순간 그 에너지가 공기를 채우며 주변 사람들까지 활기차게 만드는 것을 느낄 것입니다. 온종일 에너지가 떨어지지 않는 이 특별한 날을 최대한 활용해 당신만의 족적을 남기세요.', en: 'Leo\'s unique life force is abundant today, and when you enter a room your energy fills the air and energizes everyone around you. This is the rare kind of day where your stamina never flags and your presence radiates an almost magnetic warmth. Make the most of this exceptional day and leave your mark on it.', zh: '狮子座特有的生命力充沛。当你走进房间时，你的能量充满空气，连周围的人都会活跃起来。整天能量不会下降——充分利用这特别的一天，留下属于你的足迹。', ja: '獅子座特有の生命力が満ちています。あなたが部屋に入った瞬間そのエネルギーが空気を満たし周りの人々さえ活気づかせるのを感じるでしょう。一日中エネルギーが落ちないこの特別な日を最大限に活かして、あなただけの足跡を残してください。', es: 'La fuerza vital única de Leo abunda hoy, y cuando entras a un lugar tu energía llena el aire y energiza a todos a tu alrededor. Aprovecha al máximo este día excepcional donde tu resistencia nunca decae y deja tu huella.' },
      { ko: '마음먹은 다이어트나 운동 계획을 오늘 시작하면 성공 확률이 높습니다. 오늘의 강력한 에너지가 첫 번째 실천을 쉽고 자연스럽게 만들어줄 것이며, 그 첫 발걸음이 이후의 모든 동력이 됩니다. 내일로 미루지 말고 오늘 당장 첫 번째 행동을 취하세요—사자자리에게 지금이 가장 완벽한 순간입니다.', en: 'Starting a planned diet or exercise today carries remarkably high success rates, with today\'s powerful energy making that first action feel easy and natural. That very first step becomes the momentum that drives everything that follows. Don\'t delay until tomorrow—take your first action right now, because for Leo, this is the most perfect moment.', zh: '今天开始计划中的减肥或运动计划成功率极高。今天强大的能量将使第一次实践变得容易自然，那第一步将成为之后所有动力的源泉。不要拖到明天，立即采取第一个行动——对狮子座来说，现在是最完美的时刻。', ja: '心に決めたダイエットや運動計画を今日始めれば成功確率が高いです。今日の強力なエネルギーが最初の実践を楽で自然なものにしてくれ、その第一歩がその後の全ての動力になります。明日に先送りせず今すぐ最初の行動を起こしてください——獅子座にとって今が最も完璧な瞬間です。', es: 'Comenzar hoy una dieta o plan de ejercicio tiene probabilidades de éxito notablemente altas, con la poderosa energía de hoy haciendo que esa primera acción se sienta fácil y natural. No pospongas hasta mañana—toma tu primera acción ahora mismo, porque para Leo, este es el momento más perfecto.' },
    ],
    medium: [
      { ko: '심장과 등 건강에 신경 쓰는 하루를 보내세요. 태양의 별자리인 사자자리는 심장이 특히 예민한데, 오늘은 그 부분에 조금 더 주의를 기울일 기회입니다. 가벼운 스트레칭이나 호흡 운동으로 몸의 소리에 귀 기울이면, 몸이 스스로 무엇이 필요한지 말해줄 것입니다.', en: 'Spend the day mindful of heart and back health—as the sun\'s own sign, Leo\'s heart is an energetically sensitive area worth tending. Today presents a hidden opportunity to tune into your body\'s subtle messages before they become louder. Light stretching or breathing exercises will help you listen, and your body will tell you exactly what it needs.', zh: '注意心脏和背部健康的一天。作为太阳星座，狮子座的心脏特别敏感，今天是对那个部位多加关注的机会。通过轻度拉伸或呼吸运动倾听身体的声音，身体自然会告诉你它需要什么。', ja: '心臓と背中の健康に気を配る一日を過ごしてください。太陽の星座である獅子座は心臓が特に繊細ですが、今日はその部分に少し注意を向ける機会です。軽いストレッチや呼吸運動で体の声に耳を傾ければ、体が自ら必要なものを語りかけてくれます。', es: 'Pasa el día cuidando la salud del corazón y la espalda—como el signo del sol, el corazón de Leo es un área energéticamente sensible. Esta es la oportunidad oculta de sintonizar con los mensajes sutiles de tu cuerpo. Los estiramientos ligeros te ayudarán a escuchar lo que tu cuerpo necesita.' },
      { ko: '과식이나 과음의 유혹이 있을 수 있습니다. 사자자리는 삶의 풍요로움을 온몸으로 즐기는 기질이 있어, 이 유혹이 더 강하게 느껴질 수 있습니다. 적당한 절제가 건강의 비결임을 알면서도 어렵다면, 즐거움의 질을 높이는 방향—더 좋은 것을 더 적게—으로 접근해보세요.', en: 'Temptations of overeating or overdrinking may arise today, and for Leo who naturally embraces life\'s richness with full intensity, these urges can feel particularly strong. The honest observation is that moderation doesn\'t mean deprivation—it means elevating quality over quantity. Savor less of something better, and you\'ll find more genuine satisfaction.', zh: '可能有过食或过饮的诱惑。狮子座有全身享受生活丰富性的气质，这种诱惑可能感觉更强烈。适度节制是健康的秘诀，如果难以做到，尝试提升享受的质量——更好的少量——而非纵情享乐。', ja: '過食や飲み過ぎの誘惑があるかもしれません。獅子座は人生の豊かさを全身で楽しむ気質があり、この誘惑がより強く感じられることがあります。適度な節制が健康の秘訣ですが難しければ、楽しみの質を高める方向——より良いものをより少なく——でアプローチしてみてください。', es: 'Pueden surgir tentaciones de comer o beber en exceso hoy, y para Leo que naturalmente abraza la riqueza de la vida con plena intensidad, estos impulsos pueden sentirse especialmente fuertes. La moderación no significa privación—significa elevar la calidad sobre la cantidad. Saborea menos de algo mejor.' },
      { ko: '충분한 수면이 내일의 활력을 좌우합니다. 오늘 밤의 투자—일찍 잠자리에 드는 것—가 내일 사자자리의 왕다운 존재감으로 돌아옵니다. 화면을 끄고 자신을 위한 고요한 밤 시간을 선물하세요—그것이 내일 당신을 빛나게 할 가장 효과적인 준비입니다.', en: 'Adequate sleep truly determines tomorrow\'s vitality, and the hidden opportunity is this: the investment of going to bed early tonight returns as Leo\'s full royal presence tomorrow. Turn off your screens and give yourself the gift of quiet evening hours. That deliberate rest is the most effective preparation for a day that will make you shine.', zh: '充足的睡眠决定明天的活力。今晚的投资——早点睡——将以狮子座的王者存在感在明天回报你。关掉屏幕，给自己一个宁静的夜晚礼物——这是让明天发光的最有效准备。', ja: '十分な睡眠が明日の活力を左右します。今夜の投資——早く就寝すること——が明日獅子座の王らしい存在感として戻ってきます。画面を消して自分のための静かな夜の時間をプレゼントしてください——それが明日あなたを輝かせる最も効果的な準備です。', es: 'El sueño adecuado determina la vitalidad de mañana, y la oportunidad oculta es esta: la inversión de acostarse temprano esta noche regresa como la plena presencia real de Leo mañana. Apaga tus pantallas y regálate horas vespertinas tranquilas—ese descanso deliberado es la preparación más efectiva.' },
      { ko: '격렬한 운동보다 요가나 산책 같은 부드러운 활동이 어울리는 날입니다. 강렬함을 사랑하는 사자자리에게는 느린 움직임이 오히려 더 어려울 수 있지만, 오늘은 그 조용한 힘 안에 숨어 있는 깊은 회복력을 발견할 기회입니다. 산책 중 떠오르는 아이디어가 당신을 놀라게 할 것입니다.', en: 'Gentle activities like yoga or walking suit today better than intense exercise—and for intensity-loving Leo, slowing down can actually be the harder challenge. But today holds a hidden opportunity in that quiet power: the profound recovery and clarity that gentle movement brings. The ideas that arise during a walk may genuinely surprise you.', zh: '比起剧烈运动，瑜伽或散步等柔和的活动更适合今天。对热爱强烈的狮子座来说，放慢脚步实际上可能更具挑战，但今天在那份宁静的力量中隐藏着深刻的恢复力。散步中浮现的想法可能会让你惊喜。', ja: '激しい運動よりヨガや散歩のような穏やかな活動が似合う日です。激しさを愛する獅子座には遅い動きがむしろより難しいかもしれませんが、今日はその静かな力の中に隠れている深い回復力を発見する機会です。散歩中に浮かぶアイデアがあなたを驚かせるでしょう。', es: 'Actividades suaves como yoga o caminar son más adecuadas hoy—y para Leo amante de la intensidad, desacelerar puede ser el verdadero desafío. Pero hoy hay una oportunidad oculta en ese poder tranquilo: la profunda recuperación que trae el movimiento gentil. Las ideas que surjan durante un paseo te sorprenderán.' },
      { ko: '스트레스가 쌓이기 전에 자신만의 해소법을 실천하세요. 사자자리는 외적으로 강해 보이지만 내면에서는 더 많은 것을 느끼기 때문에, 에너지 관리가 더욱 중요합니다. 오늘 10분이라도 자신을 위한 시간을 만들면, 이후 몇 시간의 에너지가 완전히 달라질 것입니다.', en: 'Practice your own stress-relief methods before stress builds up today, because Leo\'s outer strength often conceals an inner landscape that feels even more intensely. That sensitivity is your power, not a weakness—but it needs tending. Even ten minutes carved out for yourself today will transform the quality of energy you bring to everything that follows.', zh: '在压力积累之前实践自己的缓解方法。狮子座外表强大，但内心感受更深，因此能量管理更加重要。今天哪怕抽出10分钟为自己的时间，之后几小时的能量质量将完全不同。', ja: 'ストレスが溜まる前に自分なりの解消法を実践してください。獅子座は外見上は強そうに見えても内面ではより多くを感じているため、エネルギー管理がより重要です。今日10分でも自分のための時間を作れば、その後数時間のエネルギーが全く変わるでしょう。', es: 'Practica tus métodos de alivio de estrés antes de que se acumule, porque la fortaleza exterior de Leo a menudo oculta un paisaje interior que siente con más intensidad. Incluso diez minutos para ti mismo hoy transformarán la calidad de energía que aportas a todo lo que sigue.' },
      { ko: '햇볕을 적당히 쬐면 기분과 건강 모두 좋아집니다. 태양에 지배받는 사자자리에게 햇빛은 단순한 자연 현상이 아닌, 당신의 에너지 원천과 직결된 특별한 연료입니다. 오늘 잠깐이라도 햇볕 아래 서세요—그 빛이 당신의 기분을 반전시키는 마법 같은 순간을 경험할 것입니다.', en: 'Moderate sun exposure improves both mood and health today, and for Leo ruled by the sun, sunlight is not just a natural phenomenon but a special fuel connected to your energy source. Take even a few minutes to stand in the sunshine today—you\'ll experience that almost magical moment when the light shifts your mood and restores your sense of self.', zh: '适当晒太阳对心情和健康都好。对受太阳支配的狮子座来说，阳光不只是自然现象，而是与你能量源泉直接相连的特殊燃料。今天哪怕短暂站在阳光下——你将体验到那光芒改变你心情的神奇瞬间。', ja: '適度に日光を浴びると気分も健康も良くなります。太陽に支配される獅子座にとって日光は単なる自然現象ではなく、あなたのエネルギー源と直結した特別な燃料です。今日少しでも日差しの下に立ってみてください——その光があなたの気分を一変させる魔法のような瞬間を体験するでしょう。', es: 'La exposición moderada al sol mejora tanto el ánimo como la salud hoy, y para Leo regido por el sol, la luz solar es un combustible especial conectado a tu fuente de energía. Tómate unos minutos para pararte al sol hoy—experimentarás ese momento casi mágico cuando la luz transforma tu estado de ánimo.' },
      { ko: '자세가 무너지기 쉬운 날입니다. 사자자리의 당당한 자세는 단순히 외모의 문제가 아니라 자신감과 에너지를 유지하는 신체적 앵커 역할을 합니다. 의식적으로 바른 자세를 유지하면, 그것이 다시 당신의 내면 상태를 더 강하고 자신 있게 만들어줄 것입니다.', en: 'Posture tends to deteriorate today, but for Leo, standing tall is not just about appearance—it\'s a physical anchor for confidence and sustaining your unique energy. The hidden opportunity here is the mind-body feedback loop: consciously maintaining good posture will in turn make your inner state feel stronger and more confident. Stand like the lion you are.', zh: '容易驼背的一天。狮子座的挺拔姿势不仅仅是外观问题，它是维持自信和能量的身体锚点。有意识地保持正确姿势，将反过来让你的内心状态更强大、更自信——像狮子一样站立。', ja: '姿勢が崩れやすい日です。獅子座の堂々とした姿勢は単なる外見の問題ではなく、自信とエネルギーを維持するための身体的なアンカーです。意識的に正しい姿勢を維持すると、それが再びあなたの内なる状態をより強く自信に満ちたものにしてくれます。ライオンのように立ってください。', es: 'La postura tiende a deteriorarse hoy, pero para Leo, mantenerse erguido no es solo apariencia—es un ancla física para la confianza. La oportunidad oculta aquí es el bucle mente-cuerpo: mantener conscientemente una buena postura hará que tu estado interior se sienta más fuerte y seguro. Párate como el león que eres.' },
      { ko: '비타민과 수분 섭취에 더 신경 써보세요. 사자자리는 에너지를 많이 쓰는 만큼 몸에 필요한 것들을 빠르게 소모합니다. 오늘 물 한 잔을 더 마시고 영양소를 챙기는 이 작은 행동이, 일주일 후 당신의 활력과 집중력을 눈에 띄게 높여줄 것입니다.', en: 'Pay more attention to vitamin and water intake today, because Leo\'s high-energy nature burns through what the body needs more quickly than most. This small act of care—one extra glass of water, a mindful nutritional choice—creates a compounding effect you\'ll notice in your vitality and focus within a week. Small care truly makes a profound difference.', zh: '更注意维生素和水分的摄取。狮子座消耗大量能量，因此身体需要的东西消耗更快。今天多喝一杯水、注意营养摄取的小小行动，将在一周内显著提升你的活力和专注力。', ja: 'ビタミンと水分摂取にもっと気を配ってみてください。獅子座はエネルギーをたくさん使う分、体に必要なものを速く消費します。今日水を一杯多く飲み栄養素に気を配るこの小さな行動が、一週間後あなたの活力と集中力を目に見えて高めてくれるでしょう。', es: 'Presta más atención a la ingesta de vitaminas y agua hoy, porque la naturaleza de alto consumo energético de Leo agota lo que el cuerpo necesita más rápidamente. Este pequeño acto de cuidado—un vaso extra de agua, una elección nutricional consciente—crea un efecto compuesto notable en tu vitalidad en una semana.' },
      { ko: '무리한 체력 소모보다 규칙적인 생활 리듬을 유지하는 것이 중요합니다. 극적인 변화를 좋아하는 사자자리에게 루틴은 지루하게 느껴질 수 있지만, 지속 가능한 에너지의 비밀은 바로 그 일상적인 리듬 안에 숨어 있습니다. 오늘 하루의 규칙적인 패턴이 내일의 폭발적인 에너지를 만들어냅니다.', en: 'Maintaining regular life rhythms is more important than exhausting your stamina today. For Leo who loves dramatic action, a steady routine can feel boring—but the hidden truth is that sustainable energy lives inside that ordinary rhythm. Today\'s consistent patterns are quietly building tomorrow\'s explosive power.', zh: '比起过度消耗体力，维持规律的生活节奏更重要。对热爱戏剧性变化的狮子座来说，规律可能感觉无聊，但可持续能量的秘密就藏在那日常节奏中。今天规律的模式正在悄悄积累明天的爆发力。', ja: '無理な体力消耗より規則的な生活リズムを維持することが重要です。劇的な変化を好む獅子座にはルーティンが退屈に感じられるかもしれませんが、持続可能なエネルギーの秘密はその日常的なリズムの中に隠れています。今日の規則的なパターンが明日の爆発的なエネルギーを生み出します。', es: 'Mantener ritmos de vida regulares es más importante que agotar tu resistencia hoy. Para Leo que ama la acción dramática, una rutina constante puede sentirse aburrida—pero el poder explosivo de mañana se construye silenciosamente en los patrones consistentes de hoy.' },
      { ko: '건강 검진을 미루고 있다면 오늘 일정을 잡아보세요. 사자자리는 강하다는 이미지 때문에 몸의 작은 신호를 무시하는 경향이 있지만, 진정한 왕은 자신의 가장 소중한 자산인 몸을 먼저 지킵니다. 오늘 예약 전화 한 통이 미래의 당신에게 줄 수 있는 가장 큰 선물입니다.', en: 'If you\'ve been delaying health check-ups, schedule one today—Leo\'s strong image can make it tempting to ignore the body\'s small signals, but a true king protects their most precious asset first. The small action of making that appointment call today is genuinely one of the greatest gifts you can give your future self. Prevention is always the best cure.', zh: '如果一直推迟体检，今天安排一下。狮子座因为强大的形象而倾向于忽视身体的小信号，但真正的王者首先保护自己最珍贵的资产——身体。今天一个预约电话是你能给未来自己最大的礼物。', ja: '健康診断を先延ばしにしているなら今日予定を入れてみてください。獅子座は強いというイメージのため体の小さなサインを無視しがちですが、真の王は最も大切な資産である体をまず守ります。今日予約の電話一本が未来のあなたに与えられる最大のプレゼントです。', es: 'Si has pospuesto chequeos médicos, programa uno hoy—la fuerte imagen de Leo puede tentarte a ignorar las pequeñas señales del cuerpo, pero un verdadero rey protege primero su activo más precioso. La pequeña acción de hacer esa llamada hoy es uno de los mayores regalos que puedes darte a tu yo futuro.' },
    ],
    low: [
      { ko: '심장과 혈압에 특별히 주의하세요. 사자자리는 감정의 강도가 강해서 흥분과 분노가 더 빠르게 심장에 영향을 미칠 수 있습니다. 오늘은 반응하기 전에 잠시 숨을 고르는 습관이 당신의 심장을 지키는 가장 강력한 보호막이 됩니다.', en: 'Pay special attention to heart and blood pressure today—Leo\'s emotional intensity runs deep, and excitement or anger can affect the heart more rapidly than for other signs. This is not a weakness but a signal worth honoring. Before you react today, take one breath to pause. That single habit is the most powerful shield protecting your heart.', zh: '特别注意心脏和血压。狮子座情感强度大，兴奋和愤怒可能更快影响心脏——这不是弱点，而是值得尊重的信号。今天在反应之前停顿一口气的习惯，是保护心脏最强大的盾牌。', ja: '心臓と血圧に特に注意してください。獅子座は感情の強度が強く、興奮や怒りがより素早く心臓に影響を与えることがあります。これは弱さではなく尊重すべきシグナルです。今日は反応する前に少し息を整える習慣があなたの心臓を守る最も強力な盾となります。', es: 'Presta especial atención al corazón y la presión arterial hoy—la intensidad emocional de Leo es profunda, y la emoción o ira pueden afectar el corazón más rápidamente. Esta no es una debilidad, sino una señal que merece respeto. Antes de reaccionar hoy, toma un respiro—ese único hábito es el escudo más poderoso para proteger tu corazón.' },
      { ko: '무리한 운동은 부상의 위험이 있습니다. 강하다는 자부심이 강한 사자자리에게 쉬는 것은 패배처럼 느껴질 수 있지만, 오늘의 휴식은 내일의 더 강한 자신을 위한 전략적 투자입니다. 몸이 회복을 요청하고 있다면, 그 요청에 응답하는 것이 진정한 용기입니다.', en: 'Excessive exercise risks injury today—and for Leo whose pride in strength runs deep, resting can feel like defeat. But that feeling is the very thing to normalize: today\'s rest is a strategic investment in tomorrow\'s stronger self. If your body is requesting recovery, answering that call is the truest form of courage you can show today.', zh: '过度运动有受伤的风险。对自尊心强的狮子座来说，休息可能感觉像失败，但今天的休息是为明天更强大的自己的战略投资。如果身体在请求恢复，回应那个请求才是真正的勇气。', ja: '無理な運動は怪我の危険があります。強さに誇りを持つ獅子座には休むことが敗北のように感じられるかもしれませんが、今日の休息は明日のより強い自分への戦略的投資です。体が回復を求めているなら、その求めに応えることが真の勇気です。', es: 'El ejercicio excesivo arriesga lesiones hoy—y para Leo cuyo orgullo en la fortaleza es profundo, descansar puede sentirse como derrota. Pero el descanso de hoy es una inversión estratégica en el yo más fuerte de mañana. Si tu cuerpo está pidiendo recuperación, responder a esa llamada es la forma más verdadera de coraje.' },
      { ko: '등과 척추에 부담이 갈 수 있습니다. 사자자리는 긴장할 때 등과 어깨에 스트레스가 집중되는 경향이 있는데, 오늘은 그 부위에 특별한 주의가 필요합니다. 무거운 물건을 들거나 장시간 앉아 있을 때 의식적으로 몸을 점검하면, 더 큰 통증을 예방할 수 있습니다.', en: 'Back and spine may be strained today—and Leo tends to hold tension in the back and shoulders when under stress, making this an area that deserves extra awareness. Be careful when lifting heavy objects, and if you\'ve been sitting for long periods, consciously check in with your body. That small attention now prevents the larger pain later.', zh: '背部和脊椎可能受到负担。狮子座在紧张时往往将压力集中在背部和肩膀，今天那个部位需要特别注意。搬重物或长时间久坐时有意识地检查身体，可以预防更大的疼痛。', ja: '背中と脊椎に負担がかかることがあります。獅子座は緊張する時に背中と肩にストレスが集中する傾向があり、今日はその部位に特別な注意が必要です。重い物を持つ時や長時間座っている場合に意識的に体を点検すれば、より大きな痛みを予防できます。', es: 'La espalda y columna pueden sufrir tensión hoy—Leo tiende a concentrar la tensión en la espalda y hombros bajo estrés. Sé cuidadoso al levantar objetos pesados, y si has estado sentado mucho tiempo, revisa conscientemente tu cuerpo. Esa pequeña atención ahora previene el dolor mayor después.' },
      { ko: '스트레스가 몸으로 나타날 수 있습니다. 두통, 피로, 소화 문제처럼 몸이 보내는 신호들은 사실 당신의 마음이 과부하 상태임을 알려주는 메시지입니다. 긴장을 풀어주는 시간을 반드시 가지세요—그 짧은 휴식이 남은 하루를 완전히 다르게 만들어줄 것입니다.', en: 'Stress may manifest physically today through headaches, fatigue, or digestive unease—and these signals from your body are messages that your mind is carrying too much. This is entirely normal, and it doesn\'t mean you\'re weak. Be sure to take time to release tension; that short respite will make the rest of the day feel completely different.', zh: '压力可能以身体症状表现，如头痛、疲劳或消化问题——这些来自身体的信号实际上是你的心灵处于超负荷状态的消息。这完全正常，不代表你软弱。一定要花时间放松——那短暂的休息将让剩余的一天感觉完全不同。', ja: 'ストレスが体に現れることがあります。頭痛、疲労、消化の問題のように体が送るサインは実はあなたの心が過負荷状態であることを伝えるメッセージです。これは完全に正常で弱さを意味しません。必ず緊張をほぐす時間を持ってください——その短い休憩が残りの一日を全く変えてくれます。', es: 'El estrés puede manifestarse físicamente hoy con dolores de cabeza, fatiga o malestar digestivo—y estas señales de tu cuerpo son mensajes de que tu mente lleva demasiado. Esto es completamente normal. Asegúrate de tomarte tiempo para liberar tensión; ese breve respiro hará que el resto del día se sienta completamente diferente.' },
      { ko: '과로의 신호를 무시하지 마세요. 지속적인 피로, 의욕 저하, 집중력 감소는 당신의 몸이 SOS를 보내는 것입니다. 왕도 쉬어야 전투를 계속할 수 있듯이, 지금 잠시 멈추는 것이 더 오래, 더 강하게 빛날 수 있는 유일한 방법입니다.', en: 'Don\'t ignore overwork signals—persistent fatigue, diminished drive, and difficulty concentrating are your body sending out an SOS. The struggle to stop is real when you\'re Leo and quitting feels foreign to your nature. But just as a king must rest to continue winning battles, pausing now is the only way to shine longer and stronger. Honor that need today.', zh: '不要忽视过劳的信号——持续的疲劳、意欲减退和注意力下降是身体在发SOS信号。如同国王需要休息才能继续战斗，现在暂时停下是你能更久、更强地发光的唯一方式。今天尊重这个需求。', ja: '過労のサインを無視しないでください。持続的な疲労、意欲の低下、集中力の減少はあなたの体がSOSを送っているサインです。王も休んでこそ戦いを続けられるように、今少し立ち止まることがより長く、より強く輝ける唯一の方法です。今日その必要性を大切にしてください。', es: 'No ignores las señales de exceso de trabajo—la fatiga persistente, la motivación disminuida y la dificultad para concentrarse son el SOS de tu cuerpo. Igual que un rey debe descansar para continuar ganando batallas, pausar ahora es la única forma de brillar más tiempo y con más fuerza. Honra esa necesidad hoy.' },
      { ko: '수면 부족이 누적되고 있습니다. 사자자리답게 에너지가 넘쳐야 한다는 압박감이 정작 쉬는 것을 방해하고 있지는 않은지 생각해보세요. 오늘만큼은 충분한 수면을 취하세요—내일 아침 일어났을 때의 그 개운함이, 모든 것이 달라진다는 것을 몸으로 느끼게 해줄 것입니다.', en: 'Sleep debt is accumulating, and it\'s worth asking whether Leo\'s internal pressure to always overflow with energy is actually getting in the way of real rest. That pressure is valid, but it\'s also working against you right now. Get enough sleep at least today—when you wake tomorrow feeling genuinely refreshed, your body will confirm that everything changes when you honor its needs.', zh: '睡眠不足在累积。值得思考的是，狮子座想要永远充满能量的内在压力是否反而妨碍了真正的休息。至少今天充分睡眠——明天早上醒来时的那份清爽感，会让你亲身体验到一切都会不同。', ja: '睡眠不足が蓄積しています。獅子座らしくエネルギーがあふれていなければならないという内的プレッシャーが実は休むことを妨げていないか考えてみてください。今日だけは十分な睡眠を取ってください——明日の朝目覚めた時のその爽快感が、全てが変わることを体で感じさせてくれるでしょう。', es: 'La deuda de sueño se acumula, y vale la pena preguntarse si la presión interna de Leo por siempre desbordarse de energía está impidiendo el descanso real. Duerme lo suficiente al menos hoy—al despertar mañana genuinamente renovado, tu cuerpo confirmará que todo cambia cuando honras sus necesidades.' },
      { ko: '불규칙한 식사가 건강을 해치고 있습니다. 바쁠수록 자신을 돌보는 것을 뒤로 미루는 경향이 있는데, 오늘은 그 패턴에 잠시 주목하는 것이 필요합니다. 규칙적인 식사 습관을 회복하는 것—단 하루라도 제때 세 끼를 먹는 것—이 몸이 다시 안정을 찾는 신호를 보내기 시작할 것입니다.', en: 'Irregular meals are harming your health, and there\'s often a pattern worth noticing: the busier and more stretched Leo gets, the more self-care moves to the back of the list. Today, gently turn that attention back toward yourself. Even one day of eating three regular meals at proper times will signal your body that stability is returning—and it will respond with more energy.', zh: '不规律的饮食在损害健康。越忙越容易把自我照顾推后——今天需要短暂关注这个模式。恢复规律的饮食习惯——哪怕只是一天按时吃三餐——将开始向身体发出恢复稳定的信号。', ja: '不規則な食事が健康を害しています。忙しいほど自分のケアを後回しにする傾向があり、今日はそのパターンに少し注目することが必要です。規則的な食事習慣を回復すること——たった一日でも時間通りに三食食べること——が体が再び安定を取り戻すシグナルを送り始めるでしょう。', es: 'Las comidas irregulares están dañando tu salud, y hay un patrón que vale la pena notar: cuanto más ocupado y extendido está Leo, más el autocuidado pasa al final de la lista. Hoy, devuelve suavemente esa atención hacia ti mismo. Incluso un día de tres comidas regulares enviará a tu cuerpo la señal de que la estabilidad regresa.' },
      { ko: '감정적 스트레스가 소화 기관에 영향을 줄 수 있습니다. 장과 마음의 연결은 생각보다 훨씬 깊어서, 해결되지 않은 감정들이 말 그대로 속을 불편하게 만들기도 합니다. 마음의 평화를 우선하세요—오늘 그 내면의 소란을 잠재우면, 몸도 함께 안정을 찾을 것입니다.', en: 'Emotional stress may affect your digestive organs today—and the gut-mind connection runs far deeper than most realize. Unresolved emotions can literally create physical discomfort in your stomach. Prioritize peace of mind today: when you quiet that inner turbulence, your body will find its balance too, and you\'ll move toward tomorrow with genuine calm.', zh: '情绪压力可能影响消化器官。肠道与心灵的联系比想象的深得多，未解决的情绪会字面意义上让胃不舒服。今天优先考虑心灵平和——当你平息内心的骚动，身体也会随之稳定，你将以真正的平静迎接明天。', ja: '感情的ストレスが消化器官に影響を与えることがあります。腸と心の繋がりは思ったよりずっと深く、解決されていない感情が文字通りお腹を不快にさせることがあります。心の平和を優先してください——今日その内なる騒乱を鎮めれば体も共に安定を取り戻し、真の穏やかさで明日に向かえます。', es: 'El estrés emocional puede afectar los órganos digestivos hoy—y la conexión intestino-mente es mucho más profunda de lo que la mayoría reconoce. Las emociones sin resolver pueden literalmente crear incomodidad física. Prioriza la paz mental: cuando calles esa turbulencia interior, tu cuerpo encontrará su equilibrio también.' },
      { ko: '자존심 때문에 아픈 곳을 참지 마세요. 강하게 보여야 한다는 느낌이 때로는 도움을 구하는 것을 막는다는 것을 스스로 가장 잘 알 것입니다. 몸이 보내는 신호에 귀 기울이고, 필요하다면 망설이지 말고 도움을 구하세요—그것이 오히려 더 강한 사람이 하는 행동입니다.', en: 'Don\'t endure pain out of pride—the struggle to appear strong can sometimes be the very thing that prevents you from getting the help that would actually restore your strength. You probably know this about yourself better than anyone. Listen to your body\'s signals today, and if you need help, ask for it without hesitation—that is what truly stronger people do.', zh: '不要因为自尊心忍受疼痛。看起来强大的感觉有时会阻止寻求真正能恢复力量的帮助——你自己最清楚这一点。今天倾听身体发出的信号，如有需要，毫不犹豫地寻求帮助——那才是更强大的人所做的事。', ja: 'プライドのせいで痛いところを我慢しないでください。強く見せなければならないという感覚が時に実際に力を取り戻す助けを求めることを妨げます——これは自分が一番よく分かるでしょう。体が送るサインに耳を傾け、必要なら迷わず助けを求めてください——それがむしろより強い人のすることです。', es: 'No soportes el dolor por orgullo—la lucha por parecer fuerte a veces impide obtener la ayuda que realmente restauraría tu fuerza. Escucha las señales de tu cuerpo hoy, y si necesitas ayuda, pídela sin vacilar—eso es lo que hacen las personas verdaderamente más fuertes.' },
      { ko: '에너지가 바닥난 느낌이라면 억지로 움직이지 마세요. 이 소진된 느낌은 당신이 약한 것이 아니라, 오랫동안 너무 많은 것을 감당해왔다는 증거입니다. 쉼도 용기이며, 오늘의 멈춤이 다음 주의 당신을 다시 태양처럼 빛나게 할 에너지를 회복시켜줄 것입니다.', en: 'If energy feels depleted today, don\'t force yourself to move—and know that this exhaustion is not weakness. It is evidence that you have been carrying too much for too long. Rest is also courage, and today\'s pause is restoring the energy that will make you shine like the sun again next week. Honor the depletion; it is leading you back to your light.', zh: '如果感觉能量耗尽，不要勉强活动——请知道，这种疲惫不是软弱，而是你长时间承担太多的证明。休息也是勇气，今天的停止将恢复让你下周再次像太阳一样发光的能量。尊重这种耗尽感，它正在引领你回到自己的光芒。', ja: 'エネルギーが底を尽いた感じなら無理に動かないでください——この枯渇した感覚は弱さではなく、長い間多くを担いすぎてきた証拠です。休むことも勇気であり、今日の立ち止まりが来週あなたを再び太陽のように輝かせるエネルギーを回復させてくれます。この枯渇を大切にしてください——それがあなたの光に戻る道です。', es: 'Si sientes la energía agotada hoy, no te fuerces a moverte—y sabe que este agotamiento no es debilidad. Es evidencia de que has llevado demasiado durante demasiado tiempo. Descansar también es valentía, y la pausa de hoy está restaurando la energía que te hará brillar como el sol la próxima semana.' },
    ],
  },
  money: {
    high: [
      { ko: '재물의 태양이 빛나는 날입니다. 사자자리를 지배하는 태양이 오늘 금전 운과 완벽히 정렬되어 있어, 당신의 모든 행동이 경제적 가치로 환산되는 황금 시간대입니다. 투자나 사업에서 좋은 수익을 기대할 수 있으니, 오늘만큼은 대담하게 행동하세요.', en: 'The sun of wealth shines brilliantly today, with Leo\'s solar ruler perfectly aligned with financial fortune—making every action you take today convertible into economic value. Good returns in investments or business are genuinely within reach right now. This is your golden window; act with boldness and trust the alignment.', zh: '财富的太阳闪耀的一天。狮子座的守护星太阳今天与金钱运完美对齐，你的每个行动都能转化为经济价值。投资或事业可以期待好收益——这是你的黄金时窗，大胆行动吧。', ja: '財の太陽が輝く日です。獅子座を支配する太陽が今日金運と完璧に整列しており、あなたの全ての行動が経済的価値に換算される黄金の時間帯です。投資やビジネスで良い収益が期待できますので、今日だけは大胆に行動してください。', es: 'El sol de la riqueza brilla brillantemente hoy, con el sol de Leo perfectamente alineado con la fortuna financiera. Cada acción que tomes hoy es convertible en valor económico. Buenos rendimientos en inversiones o negocios están genuinamente al alcance—actúa con audacia.' },
      { ko: '당신의 창의력이 수입으로 직결됩니다. 사자자리의 독창적인 표현력과 카리스마가 오늘 시장에서 가장 희귀하고 귀한 자산으로 인정받을 것입니다. 아이디어를 현금화할 기회를 잡으세요—당신만이 만들 수 있는 것의 가치를 더 높이 책정하는 것이 오늘의 전략입니다.', en: 'Your creativity directly connects to income today, with Leo\'s unique expressive power and charisma recognized by the market as rare and precious assets. The ideas only you can create carry premium value right now. Seize the chance to monetize them—and don\'t undercharge for what is genuinely irreplaceable. Price your uniqueness at its true worth.', zh: '你的创造力今天直接转化为收入，狮子座独特的表达力和魅力被市场认可为稀有珍贵的资产。只有你能创造的东西今天具有溢价价值。抓住变现机会——不要低估不可替代事物的价值。', ja: 'あなたの創造力が収入に直結します。獅子座の独創的な表現力とカリスマが今日市場で最も希少で貴重な資産として認められます。アイデアを現金化するチャンスを掴んでください——あなたにしか作れないものの価値をより高く設定することが今日の戦略です。', es: 'Tu creatividad se conecta directamente con ingresos hoy, con el poder expresivo único de Leo reconocido como activos raros y valiosos en el mercado. Las ideas que solo tú puedes crear llevan valor premium ahora. Aprovecha la oportunidad de monetizarlas y no cobres de menos por lo genuinamente irremplazable.' },
      { ko: '관대하게 베풀었던 것이 풍성한 보답으로 돌아옵니다. 사자자리의 너그러운 마음이 우주의 풍요 법칙과 공명하여, 당신이 내어준 것들이 예상보다 더 큰 형태로 돌아오고 있습니다. 풍요의 순환이 시작되었으니, 이 흐름을 타고 더 크게 꿈을 그려보세요.', en: 'Your generous giving returns as abundant rewards today, with Leo\'s magnanimous heart resonating with the universe\'s law of abundance—what you have given out is coming back in forms greater than you expected. The cycle of abundance has truly begun. Ride this current and allow yourself to dream even bigger than before.', zh: '慷慨的付出以丰厚的回报归来。狮子座宽大的心与宇宙丰盛法则产生共鸣，你付出的一切正以比预期更大的形式回来。丰饶的循环已经开始——乘上这股浪潮，做更大的梦吧。', ja: '寛大に分け与えたものが豊かな報いとして戻ってきます。獅子座の寛大な心が宇宙の豊かさの法則と共鳴し、あなたが与えたものが予想より大きな形で戻ってきています。豊かさの循環が始まりましたので、この流れに乗ってより大きく夢を描いてください。', es: 'Tu generosidad regresa como abundantes recompensas hoy, con el corazón magnánimo de Leo resonando con la ley de abundancia del universo. El ciclo de abundancia ha comenzado verdaderamente. Cabalga esta corriente y permítete soñar aún más grande que antes.' },
      { ko: '예상치 못한 금전적 행운이 찾아옵니다. 오늘은 계획에 없던 방향에서 돈이나 기회가 들어오는 날로, 열린 마음으로 모든 가능성을 받아들이세요. 보너스나 선물, 혹은 뜻밖의 사업 제안이 당신의 하루를 완전히 바꿔놓을 수 있습니다.', en: 'Unexpected financial luck comes your way today, with money and opportunities arriving from directions you hadn\'t planned for. Stay open-minded and receptive to all possibilities that present themselves. A bonus, a gift, or an unexpected business proposal could arrive and completely transform your day—be ready to say yes.', zh: '意想不到的金钱好运来了。今天钱和机会从意想不到的方向涌来，保持开放心态接受所有可能性。奖金、礼物或意外的商业提案可能完全改变你的一天——准备好说是。', ja: '予想外の金銭的幸運が訪れます。今日は計画になかった方向からお金や機会が入ってくる日で、開かれた心で全ての可能性を受け入れてください。ボーナスやプレゼント、または思いがけないビジネス提案があなたの一日を完全に変えることがあります。', es: 'Llega suerte financiera inesperada hoy, con dinero y oportunidades llegando de direcciones que no habías planeado. Mantente abierto y receptivo a todas las posibilidades. Un bono, un regalo o una propuesta de negocio inesperada podría llegar y transformar completamente tu día—prepárate para decir sí.' },
      { ko: '과감한 투자 결정이 성공으로 이어지는 날입니다. 사자자리의 직감은 오늘 특히 예리하게 작동하고 있어, 논리보다 먼저 맞는 방향을 감지할 것입니다. 직감을 신뢰하고 망설임 없이 결정을 내리세요—오늘의 대담함이 내일의 수익으로 증명될 것입니다.', en: 'Bold investment decisions lead to success today, and Leo\'s intuition is operating with exceptional sharpness—sensing the right direction even before logic catches up. Trust that intuition and make your decision without hesitation. The boldness you exercise today will be proven by tomorrow\'s returns, validating exactly what you felt was right.', zh: '大胆的投资决定通向成功的一天。狮子座的直觉今天特别敏锐，甚至在逻辑跟上之前就能感知正确的方向。相信直觉，毫不犹豫地做出决定——今天的大胆将被明天的收益所证明。', ja: '大胆な投資決定が成功につながる日です。獅子座の直感は今日特に鋭く働いており、論理が追いつく前に正しい方向を感知します。直感を信頼して迷わず決断してください——今日の大胆さが明日の収益によって証明されるでしょう。', es: 'Las decisiones de inversión audaces llevan al éxito hoy, y la intuición de Leo opera con agudeza excepcional—sintiendo la dirección correcta antes de que la lógica alcance. Confía en esa intuición y toma tu decisión sin vacilar. La audacia que ejerces hoy será probada por los rendimientos de mañana.' },
      { ko: '새로운 수입원이 열리는 시기입니다. 오랫동안 마음속에서만 키워온 아이디어가 있다면, 지금이 바로 그것을 세상으로 꺼내야 할 황금 타이밍입니다. 부업이나 사이드 프로젝트를 시작하세요—첫 번째 작은 발걸음이 예상치 못한 수입의 문을 활짝 열어줄 것입니다.', en: 'A time when new income sources open, and if you have an idea that you\'ve been nurturing privately for a long time, this is the golden moment to bring it into the world. Start a side job or project today—the first small step will swing open the door to income you hadn\'t anticipated. The universe is ready to fund Leo\'s dreams right now.', zh: '新收入来源打开的时期。如果你有一个长期在心中酝酿的想法，现在正是把它带入世界的黄金时机。开始副业或副项目——第一小步将敞开意想不到的收入之门。', ja: '新しい収入源が開かれる時期です。長い間心の中で育ててきたアイデアがあるなら、今がまさにそれを世に出すべき黄金のタイミングです。副業やサイドプロジェクトを始めてください——最初の小さな一歩が予想外の収入の扉を大きく開いてくれるでしょう。', es: 'Un momento en que nuevas fuentes de ingreso se abren, y si tienes una idea que has estado nutriendo privadamente por mucho tiempo, este es el momento dorado para traerla al mundo. Comienza un proyecto secundario hoy—el primer pequeño paso abrirá la puerta a ingresos que no habías anticipado.' },
      { ko: '금전적 협상에서 유리한 결과를 얻습니다. 사자자리의 카리스마와 자신감이 오늘 협상 테이블에서 강력한 설득력으로 작용합니다. 당당하게 자신의 가치를 요구하세요—당신이 생각하는 것보다 높은 금액을 불러도 상대방이 고개를 끄덕이는 경험을 할 것입니다.', en: 'Gain favorable results in financial negotiations today, with Leo\'s charisma and confidence acting as powerful persuasive forces at the table. Confidently demand your true worth—in fact, name a higher number than you think is justified, because you may discover that others are more ready to agree than you expected. Today, Leo\'s presence commands premium value.', zh: '在金钱谈判中获得有利结果。狮子座的魅力和自信今天在谈判桌上发挥强大的说服力。自信地要求自己的价值——你可能会发现，即使提出比预期更高的数字，对方也会点头同意。', ja: '金銭的な交渉で有利な結果を得ます。獅子座のカリスマと自信が今日交渉テーブルで強力な説得力として作用します。堂々と自分の価値を要求してください——あなたが思うより高い金額を提示しても相手が頷く経験をするでしょう。', es: 'Obtén resultados favorables en negociaciones financieras hoy, con el carisma y confianza de Leo actuando como fuerzas persuasivas en la mesa. Exige tu verdadero valor con confianza—de hecho, nombra un número más alto del que crees justificado, porque hoy la presencia de Leo comanda valor premium.' },
      { ko: '오랫동안 기다렸던 금전적 성과가 드디어 실현됩니다. 포기하고 싶었던 순간들을 버텨온 당신의 인내가 오늘 그 빛을 발합니다. 이 보상을 온전히 받아들이고, 다음 꿈을 향한 첫 번째 투자를 계획하세요—당신은 이것을 받을 자격이 충분합니다.', en: 'Long-awaited financial results finally materialize today—the patience you maintained through all the moments you wanted to give up is now paying off in a very real way. Accept this reward fully and without guilt; you have earned it through genuine perseverance. Now let it inspire your first investment toward the next dream on your horizon.', zh: '等待已久的经济成果终于实现。你在想放弃的时刻坚持下来的耐心今天绽放光芒。完全接受这份奖励，为下一个梦想的第一次投资做计划——你完全值得拥有这一切。', ja: '長い間待っていた金銭的な成果がついに実現します。諦めたかった瞬間を乗り越えてきたあなたの忍耐が今日その光を放ちます。この報酬を十分に受け取り、次の夢に向けた最初の投資を計画してください——あなたはこれを受け取る資格が十分あります。', es: 'Los resultados financieros largamente esperados finalmente se materializan hoy—la paciencia que mantuviste a través de todos los momentos que quisiste rendirte se está pagando de manera muy real. Acepta esta recompensa completamente y sin culpa. Ahora deja que inspire tu primera inversión hacia el próximo sueño.' },
      { ko: '현명한 소비와 투자의 균형이 잘 맞는 날입니다. 사자자리의 큰 그림을 그리는 능력과 오늘의 명석한 판단력이 만나 재정 계획을 세우기 최적의 상태입니다. 오늘 작성하는 계획 하나가 미래의 재정 자유를 향한 가장 강력한 로드맵이 될 것입니다.', en: 'Wise spending and investment are perfectly balanced today, with Leo\'s vision for the big picture combining with today\'s sharp judgment to create ideal conditions for financial planning. A plan you create today will become the most powerful roadmap toward your future financial freedom. Invest even thirty minutes in mapping where you want to be—it will pay dividends.', zh: '明智消费和投资平衡得好的一天。狮子座勾画大局的能力与今天敏锐的判断力相结合，形成最佳的理财计划状态。今天制定的一个计划将成为通向未来财务自由最有力的路线图。', ja: '賢い消費と投資のバランスが良く取れた日です。獅子座の大きな絵を描く能力と今日の明晰な判断力が合わさり財務計画を立てるのに最適な状態です。今日作成する計画が未来の財政的自由への最も強力なロードマップになるでしょう。', es: 'El gasto sabio y la inversión están perfectamente equilibrados hoy, con la visión del panorama general de Leo combinándose con el juicio agudo de hoy para crear condiciones ideales para la planificación financiera. Un plan que crees hoy se convertirá en el mapa de ruta más poderoso hacia tu libertad financiera futura.' },
      { ko: '당신의 리더십이 팀의 매출을 올리고 그 보상이 돌아옵니다. 사자자리의 타고난 리더십은 단순히 사람을 이끄는 것이 아니라, 주변의 잠재력을 끌어올려 집단적인 성과를 만들어내는 능력입니다. 오늘 그 능력이 가장 빛을 발하니, 팀을 이끌고 성공의 결실을 함께 나누세요.', en: 'Your leadership boosts team revenue today and the reward returns to you as well—because Leo\'s innate leadership is not merely directing people but elevating the potential around you to create collective results no one could achieve alone. That remarkable ability is shining brightest today. Lead the team forward and share generously in the success you create together.', zh: '你的领导力提升了团队的营收，回报也随之而来。狮子座天生的领导力不仅仅是引导人们，更是提升周围的潜力，创造没有人能单独取得的集体成果。今天那种能力最为耀眼——带领团队前进，慷慨分享共同创造的成功。', ja: 'あなたのリーダーシップがチームの売上を上げその報酬が戻ってきます。獅子座の生まれながらのリーダーシップは単に人を導くだけでなく、周囲の潜在力を引き上げて誰一人では達成できない集団的な成果を生み出す能力です。今日その能力が最も輝いていますので、チームを率いて成功の実を共に分け合ってください。', es: 'Tu liderazgo impulsa los ingresos del equipo hoy y la recompensa regresa a ti también—porque el liderazgo innato de Leo no es simplemente dirigir personas sino elevar el potencial a tu alrededor para crear resultados colectivos que nadie podría lograr solo. Esa notable habilidad brilla más hoy. Lidera el equipo hacia adelante.' },
    ],
    medium: [
      { ko: '충동적인 소비 욕구를 자제하세요. 사자자리는 아름다운 것과 좋은 것에 끌리는 감각이 남다른데, 오늘 그 감각이 지갑을 열게 만들 수 있습니다. 꼭 필요한 것인지 한번 더 생각해보세요—24시간 후에도 여전히 원하는 것이라면 그때 구매해도 늦지 않습니다.', en: 'Restrain impulsive spending urges today—Leo\'s extraordinary sensitivity to beauty and quality can make the pull toward purchasing feel especially compelling right now. The hidden opportunity is in the pause: think twice about whether something is truly necessary. If you still want it in twenty-four hours, you can buy it then. Time is the most effective filter.', zh: '克制冲动消费的欲望。狮子座对美好事物的感知力与众不同，今天这种感知可能促使你打开钱包。再想想是否真的需要——如果24小时后仍然想要，那时购买也不迟。时间是最有效的过滤器。', ja: '衝動的な消費欲求を自制してください。獅子座は美しいものや良いものに引き付けられる感覚が人並み外れており、今日その感覚が財布を開けさせることがあります。本当に必要かもう一度考えてみてください——24時間後もまだ欲しければその時購入しても遅くはありません。', es: 'Controla los impulsos de gasto hoy—la sensibilidad extraordinaria de Leo hacia la belleza y la calidad puede hacer que el impulso de comprar se sienta especialmente convincente ahora. Piensa dos veces si algo es realmente necesario. Si todavía lo quieres en veinticuatro horas, puedes comprarlo entonces—el tiempo es el filtro más efectivo.' },
      { ko: '수입과 지출의 균형을 점검하기 좋은 날입니다. 실제 숫자를 보는 것이 불안할 수 있지만, 현실을 직시하는 것이 더 큰 재정적 자유로 나아가는 첫 번째 용기입니다. 가계부를 정리해보세요—그 안에서 당신이 몰랐던 새로운 절약의 기회를 발견할 것입니다.', en: 'A good day to review the balance of income and expenses, even if looking at the actual numbers feels unsettling. That honest look is the first act of courage that leads toward greater financial freedom. Organize your ledger—you will discover opportunities for savings you hadn\'t noticed before, and that knowledge itself is a form of hidden wealth.', zh: '检查收支平衡的好日子。看实际数字可能令人不安，但正视现实是走向更大财务自由的第一勇气。整理一下记账本——你将在其中发现以前没有注意到的新节约机会。', ja: '収入と支出のバランスを点検するのに良い日です。実際の数字を見ることが不安かもしれませんが、現実を直視することがより大きな財政的自由への第一の勇気です。家計簿を整理してみてください——その中に気づかなかった新たな節約の機会を発見するでしょう。', es: 'Un buen día para revisar el balance de ingresos y gastos, aunque mirar los números reales se sienta inquietante. Esa mirada honesta es el primer acto de coraje que lleva hacia mayor libertad financiera. Organiza tu libro contable—descubrirás oportunidades de ahorro que no habías notado antes.' },
      { ko: '큰 투자보다 소액 분산투자가 안전한 시기입니다. 사자자리의 과감한 본능이 큰 도박을 원할 수 있지만, 지금은 여러 곳에 작게 나누는 것이 더 강한 전략입니다. 신중하게 접근하세요—작은 씨앗들이 함께 자라면 결국 하나의 큰 투자보다 더 풍성한 숲이 됩니다.', en: 'Small diversified investments are safer than large ones right now—and even though Leo\'s bold instincts may push for a big single bet, spreading smaller amounts across multiple opportunities is actually the stronger strategy today. Approach cautiously and plant many small seeds. When they grow together, they create a forest more abundant than any single large investment.', zh: '比起大投资，小额分散投资更安全的时期。狮子座大胆的本能可能想要大赌注，但现在将小金额分散到多处才是更强的策略。谨慎对待——小种子共同生长，最终比一次大投资创造更丰盛的森林。', ja: '大きな投資より少額分散投資が安全な時期です。獅子座の大胆な本能が大きな賭けを望むかもしれませんが、今は複数に小さく分けることがより強い戦略です。慎重にアプローチしてください——小さな種が一緒に育てば最終的に一つの大きな投資より豊かな森になります。', es: 'Las inversiones pequeñas diversificadas son más seguras que las grandes ahora—y aunque los instintos audaces de Leo pueden empujar hacia una gran apuesta única, distribuir cantidades menores en múltiples oportunidades es en realidad la estrategia más fuerte hoy. Planta muchas semillas pequeñas—juntas crean un bosque más abundante.' },
      { ko: '체면을 위한 지출을 줄이면 생각보다 많은 돈이 모입니다. 사자자리는 품격 있는 삶을 추구하는데, 그 품격이 꼭 비싼 것에서 나올 필요는 없습니다. 오늘 지출 목록을 검토하면서 진정한 당신의 가치를 드러내는 것과 그저 남에게 보여주기 위한 것을 구별해보세요—그 구별이 큰 자유를 가져다줄 것입니다.', en: 'Reducing spending for appearances saves more money than you think, and for Leo who values elegant living, it\'s worth noting that true sophistication doesn\'t have to come from expensive things. Review your spending today and separate what genuinely expresses your authentic values from what\'s purely for external validation—that distinction will bring you surprising financial freedom.', zh: '减少为了面子的支出，会攒下比想象中更多的钱。狮子座追求有品格的生活，但那种品格不必来自昂贵的东西。今天检视支出清单，区分真正体现你价值观的和只是为了给别人看的——那种区分将带来巨大的自由。', ja: '体面のための支出を減らすと思ったより多くのお金が貯まります。獅子座は品格ある暮らしを追求しますが、その品格は必ずしも高価なものから来る必要はありません。今日支出リストを見直して、真のあなたの価値を表すものと単に人に見せるためのものを区別してみてください——その区別が大きな自由をもたらすでしょう。', es: 'Reducir el gasto por apariencia ahorra más dinero del que piensas, y para Leo que valora una vida elegante, vale la pena notar que la verdadera sofisticación no tiene que venir de cosas costosas. Revisa tus gastos hoy y separa lo que genuinamente expresa tus valores de lo que es puramente para validación externa.' },
      { ko: '금전적 도움을 구하는 것이 부끄러운 일이 아닙니다. 사자자리는 혼자 모든 것을 해결해야 한다는 압박을 느끼기 쉽지만, 가장 성공한 사람들도 전문가의 조언을 구합니다. 전문가에게 상담받으세요—그 한 번의 상담이 수년간의 재정적 고민을 한꺼번에 해결해줄 통찰을 가져다줄 수 있습니다.', en: 'Seeking financial help isn\'t shameful—and while Leo often feels pressure to handle everything independently, the most successful people actively seek expert guidance. The hidden opportunity here is that one consultation could deliver insights that resolve years of financial concern in a single conversation. Consult with a professional today; asking is how the wise get wiser.', zh: '寻求金钱帮助不是丢人的事。狮子座容易感受到必须独自解决一切的压力，但最成功的人也寻求专业建议。向专业人士咨询——那一次咨询可能带来一次性解决多年财务困惑的洞察。', ja: '金銭的な助けを求めることは恥ずかしいことではありません。獅子座は一人で全てを解決しなければならないというプレッシャーを感じやすいですが、最も成功した人々も専門家のアドバイスを求めます。専門家に相談してください——その一度の相談が何年もの財政的悩みを一度に解決する洞察をもたらすことがあります。', es: 'Buscar ayuda financiera no es vergonzoso—y aunque Leo a menudo siente presión de manejar todo independientemente, las personas más exitosas buscan activamente orientación experta. Una consulta podría entregar perspectivas que resuelvan años de preocupación financiera en una sola conversación. Consulta hoy con un profesional.' },
      { ko: '오늘은 벌기보다 지키는 것에 집중하세요. 사자자리는 항상 더 크게 벌 방법을 생각하지만, 이미 있는 것을 지키는 것도 동등한 전략적 가치를 지닙니다. 절약이 곧 수입임을 기억하면서, 오늘 하루 얼마나 현명하게 지킬 수 있는지 도전해보세요.', en: 'Focus on keeping rather than earning today—Leo always thinks about how to earn more, but protecting what already exists carries equal strategic value. Saving is income, and every dollar you protect today stays in your wealth-building machine. Challenge yourself to be as brilliant at keeping as you are at creating—that balance is where lasting wealth lives.', zh: '今天专注于守住而非赚取。狮子座总在思考如何赚更多，但守住已有的东西具有同等战略价值。节约就是收入——今天挑战自己看能多聪明地守住财富，那种平衡是持久财富的所在。', ja: '今日は稼ぐより守ることに集中してください。獅子座は常により多く稼ぐ方法を考えますが、既にあるものを守ることも同等の戦略的価値を持ちます。節約がすなわち収入であることを覚えながら、今日一日どれほど賢く守れるか挑戦してみてください。', es: 'Enfócate en mantener en vez de ganar hoy—Leo siempre piensa en cómo ganar más, pero proteger lo que ya existe tiene igual valor estratégico. Ahorrar es ingreso, y cada peso que proteges hoy permanece en tu máquina de construcción de riqueza. Desafíate a ser tan brillante preservando como creando.' },
      { ko: '장기적 재정 목표를 다시 점검해보세요. 시간이 지나면서 당신이 원하는 것도 달라지게 마련인데, 예전에 세운 목표가 지금의 자신에게도 여전히 맞는지 확인해볼 기회입니다. 방향 수정이 필요하다면 지금이 가장 좋은 시기—새로운 목표를 향해 한 걸음 더 나아가는 소행동을 오늘 취하세요.', en: 'Review your long-term financial goals today, because as you evolve, what you want inevitably changes—and it\'s worth checking whether goals set in the past still align with who you are now. If course correction is needed, this is the best time to make it. Take one small action today that moves you a step closer to a revised vision that truly fits your current self.', zh: '重新审视长期财务目标。随着时间推移你想要的也会改变，值得检查过去设定的目标是否仍然适合现在的你。如果需要调整方向，现在是最好的时机——今天采取一个小行动，向更符合现在自己的修订愿景迈进一步。', ja: '長期的な財務目標を再点検してみてください。時間が経つにつれて望むものも変わるものですが、かつて設定した目標が今の自分にも合っているか確認する機会です。方向修正が必要なら今が最善の時機——新しい目標に向けて一歩近づく小さな行動を今日取ってください。', es: 'Revisa tus metas financieras a largo plazo hoy, porque a medida que evolucionas, lo que quieres inevitablemente cambia—vale la pena verificar si las metas del pasado todavía se alinean con quien eres ahora. Si se necesita corrección de rumbo, este es el mejor momento. Toma una pequeña acción hoy que te acerque a una visión revisada.' },
      { ko: '선물이나 접대 비용을 합리적으로 조절하세요. 사자자리의 넉넉한 인심이 때로 필요 이상으로 지출하게 만들 수 있는데, 관계의 질은 금액이 아닌 진심에서 나옵니다. 마음이 중요하지 금액이 아님을 기억하며, 오늘 더 창의적이고 개인적인 방식으로 상대를 감동시켜 보세요.', en: 'Adjust gift and entertainment expenses reasonably today—Leo\'s generous spirit can sometimes push spending beyond what\'s truly necessary, but the quality of relationships comes from sincerity, not size. Remember that it\'s the thought that counts, not the amount. Try being more creative and personal in how you express care today; those gestures often touch hearts more deeply than expensive ones.', zh: '合理调节礼物和招待费用。狮子座慷慨的心有时会让支出超出必要，但关系的质量来自真诚，而非金额。记住重要的是心意而非金额——今天尝试以更有创意、更个人化的方式打动对方，这样的心意往往比昂贵的礼物更能触动人心。', ja: 'プレゼントや接待の費用を合理的に調整してください。獅子座の気前の良さが時に必要以上の支出をさせることがありますが、関係の質は金額ではなく真心から生まれます。大切なのは気持ちであって金額ではないことを覚えながら、今日はより創造的で個人的な方法で相手を感動させてみてください。', es: 'Ajusta los gastos en regalos y entretenimiento razonablemente hoy—el espíritu generoso de Leo a veces puede impulsar el gasto más allá de lo necesario, pero la calidad de las relaciones viene de la sinceridad, no del tamaño. Sé más creativo y personal en cómo expresas cuidado hoy—esos gestos tocan corazones más profundamente.' },
      { ko: '정기적 저축 습관이 미래의 안정을 보장합니다. 큰 꿈을 꾸는 사자자리에게 재정적 안전망은 더 과감한 도전을 가능하게 하는 기반이 됩니다. 오늘 자동이체를 설정하는 5분이, 10년 후의 당신에게 가장 감사히 기억될 결정이 될 것입니다.', en: 'Regular saving habits guarantee future stability, and for Leo who dreams big, a financial safety net becomes the foundation that makes bolder risks possible. The five minutes you invest today in setting up automatic transfers will be remembered by your future self as one of the most grateful decisions ever made. Take that action now—small and consistent beats large and occasional every time.', zh: '定期储蓄的习惯保障未来的稳定。对于有大梦想的狮子座，财务安全网成为使更大胆的挑战成为可能的基础。今天设置自动转账的5分钟，将是10年后的你最感激的决定之一。', ja: '定期的な貯蓄習慣が将来の安定を保証します。大きな夢を見る獅子座にとって財政的な安全網はより大胆な挑戦を可能にする基盤となります。今日自動振替を設定する5分が10年後のあなたに最も感謝して記憶される決断になるでしょう。', es: 'Los hábitos de ahorro regular garantizan estabilidad futura, y para Leo que sueña en grande, una red de seguridad financiera se convierte en la base que hace posibles los riesgos más audaces. Los cinco minutos que inviertes hoy en configurar transferencias automáticas serán recordados por tu yo futuro como una de las decisiones más agradecidas.' },
      { ko: '불필요한 구독이나 회원권을 정리하면 매달 의미 있는 금액이 절약됩니다. 사람들은 이런 소소한 지출이 모이면 얼마나 큰 금액이 되는지 실제로 계산해본 적이 없는 경우가 많습니다. 오늘 30분을 투자해 구독 목록을 점검하고 사용하지 않는 것을 정리하세요—그 돈이 진정으로 원하는 것을 향해 흘러갈 수 있게 됩니다.', en: 'Canceling unnecessary subscriptions or memberships saves meaningful amounts monthly, yet most people have never actually calculated how these small ongoing costs add up to a surprisingly large annual sum. Invest thirty minutes today in reviewing your subscription list and clearing what you no longer use. That money can now flow toward what you genuinely want—and that redirect is where real abundance begins.', zh: '整理不必要的订阅或会员资格每月可以省下有意义的金额。大多数人从未实际计算这些小额持续支出累积起来有多大。今天投入30分钟检查订阅清单，清理不再使用的。那笔钱可以流向你真正想要的地方——那种重定向才是真正丰盛的开始。', ja: '不要なサブスクリプションや会員権を整理すれば毎月意味のある金額が節約できます。しかし多くの人はこのような小さな支出が積み重なるとどれほど大きな金額になるか実際に計算したことがありません。今日30分を投資してサブスクリプションリストを点検し使っていないものを整理してください——そのお金が本当に望むものに向かって流れるようになります。', es: 'Cancelar suscripciones o membresías innecesarias ahorra cantidades significativas mensualmente, pero la mayoría de las personas nunca han calculado cuánto suman estos pequeños costos continuos anualmente. Invierte treinta minutos hoy en revisar tu lista de suscripciones y eliminar lo que ya no usas. Ese dinero puede fluir ahora hacia lo que genuinamente deseas.' },
    ],
    low: [
      { ko: '과시적 소비의 유혹이 강합니다. 인정받고 싶고 멋있게 보이고 싶은 마음—그것은 사자자리의 자연스러운 욕구이며, 당신만의 문제가 아닙니다. 지갑을 열기 전에 세 번 생각하세요—지금 이 구매가 미래의 나를 더 자유롭게 하는가, 아니면 더 묶어두는가?', en: 'The temptation of showy spending is strong today—and the desire to be seen and admired is a completely natural impulse for Leo, not a personal flaw. The protective wisdom here is to pause before the wallet opens and ask one honest question: does this purchase make your future self more free, or does it tie you down? Let that answer guide you.', zh: '炫耀性消费的诱惑很强。想被认可和看起来很棒的心情——这是狮子座自然的欲求，不只是你的问题。打开钱包前想三次——这次购买让未来的自己更自由，还是更束缚？让那个答案引导你。', ja: '見栄を張る消費の誘惑が強いです。認められたい、かっこよく見られたいという気持ち——それは獅子座の自然な欲求であり、あなただけの問題ではありません。財布を開ける前に三度考えてください——今この購入が未来の自分をより自由にするのか、それとも縛り付けるのか？', es: 'La tentación del gasto ostentoso es fuerte hoy—y el deseo de ser visto y admirado es un impulso completamente natural para Leo, no un defecto personal. La sabiduría protectora es hacer una pausa antes de abrir la billetera y preguntarte honestamente: ¿Esta compra hace a tu yo futuro más libre, o lo ata? Deja que esa respuesta te guíe.' },
      { ko: '급하게 돈을 벌려는 시도는 손실을 부릅니다. 지금 이 조급함은 어쩌면 재정적 불안에서 나오는 것일 수 있는데, 그 불안 자체는 완전히 이해할 수 있는 감정입니다. 조급함을 내려놓으세요—지금 당장은 아니더라도, 당신이 꾸준히 쌓아가는 것들이 결국 가장 안정적인 형태의 부로 완성됩니다.', en: 'Rushing to make money invites losses, and the urgency you feel right now may be coming from financial anxiety—which is a completely understandable emotion. Let go of impatience today. What you build steadily and consistently, even if it doesn\'t feel quick enough right now, ultimately becomes the most durable and genuine form of wealth. Future-oriented reassurance: your time is coming.', zh: '急于赚钱会招来损失。现在这种急迫感或许来自财务焦虑——这是完全可以理解的情感。放下急躁——即使现在感觉不够快，你稳步积累的东西最终将以最稳定的形式成为财富。你的时刻终将到来。', ja: '急いでお金を稼ごうとする試みは損失を招きます。今この焦りはもしかすると財政的な不安から来ているかもしれませんが、その不安自体は完全に理解できる感情です。焦りを手放してください——今すぐではなくても、あなたが着実に積み上げているものが最終的に最も安定した形の富として完成します。', es: 'Apresurarse a ganar dinero invita pérdidas, y la urgencia que sientes ahora puede venir de ansiedad financiera—una emoción completamente comprensible. Suelta la impaciencia hoy. Lo que construyes de manera constante se convierte en la forma más duradera y genuina de riqueza. Tu tiempo está llegando.' },
      { ko: '타인에게 돈을 빌려주는 것은 신중히 판단하세요. 사자자리의 관대함은 큰 미덕이지만, 오늘은 그 관대함이 감정에 휩쓸려 나중에 후회할 결정으로 이어질 수 있는 날입니다. 감정에 휘둘리지 마세요—진정한 도움은 상대방과 자신 모두에게 지속 가능한 방식으로만 의미가 있습니다.', en: 'Judge lending money to others carefully today—Leo\'s generosity is a genuine virtue, but today that generosity can be swept by emotion into decisions you\'ll regret later. Don\'t be swayed by feelings in the moment. True help only has meaning when it\'s sustainable for both the giver and the receiver, and protecting your own financial health is never selfish.', zh: '借钱给别人要慎重判断。狮子座的慷慨是大美德，但今天那种慷慨可能被情绪卷走，导致后来后悔的决定。不要被情绪左右——真正的帮助只有在对双方都可持续的方式下才有意义，保护自己的财务健康永远不是自私。', ja: '他人にお金を貸すことは慎重に判断してください。獅子座の寛大さは大きな美徳ですが、今日はその寛大さが感情に流されて後で後悔する決断につながる日です。感情に振り回されないでください——真の助けは相手と自分両方に持続可能な方法でのみ意味があります。', es: 'Juzga con cuidado el prestar dinero a otros hoy—la generosidad de Leo es una virtud genuina, pero hoy esa generosidad puede ser arrastrada por la emoción hacia decisiones de las que te arrepentirás. No te dejes llevar por los sentimientos del momento. La verdadera ayuda solo tiene significado cuando es sostenible para ambos, el que da y el que recibe.' },
      { ko: '고위험 투자는 오늘 피하세요. 빠른 수익을 원하는 마음은 누구나 갖고 있으며, 특히 큰 것을 향해 나아가는 사자자리에게는 그 욕구가 더 강하게 느껴질 수 있습니다. 감정적 판단이 재정적 손실로 이어질 수 있는 날이니, 오늘은 지키는 것이 이기는 것임을 기억하세요.', en: 'Avoid high-risk investments today—the desire for quick returns is universal, and for Leo who always reaches for something greater, that impulse can feel especially compelling right now. But emotional judgment can lead to financial losses today in ways that set you back significantly. Remember: on some days, protecting what you have is the truest form of winning.', zh: '今天避免高风险投资。想要快速收益的心情人人都有，对于总向更大目标前进的狮子座来说，这种冲动今天可能感觉特别强烈。感情化的判断可能导致经济损失——今天记住，守住已有的才是真正的胜利。', ja: '高リスク投資は今日避けてください。素早い収益を求める気持ちは誰もが持っており、特に大きなものに向かって進む獅子座にはその欲求が今日より強く感じられるかもしれません。感情的な判断が財政的損失につながることがある日ですので、今日は守ることが勝つことであることを覚えておいてください。', es: 'Evita inversiones de alto riesgo hoy—el deseo de retornos rápidos es universal, y para Leo que siempre alcanza algo mayor, ese impulso puede sentirse especialmente convincente ahora. El juicio emocional puede llevar a pérdidas financieras hoy. Recuerda: en algunos días, proteger lo que tienes es la forma más verdadera de ganar.' },
      { ko: '충동구매 위험이 높은 날입니다. 쇼핑이 기분 전환에 도움이 된다는 것은 알지만, 오늘은 그것이 나중의 재정적 후회로 이어질 가능성이 높습니다. 쇼핑은 내일로 미루세요—24시간 후에도 여전히 원한다면, 그때는 정말 필요한 것일 테니까요.', en: 'High risk of impulse buying today—and while shopping can genuinely feel like a mood boost, today that temporary relief is likely to create financial regret later. Postpone shopping until tomorrow. If you still want it in twenty-four hours, then it\'s likely a genuine need rather than an emotional reaction. Time is your best purchasing advisor.', zh: '冲动购买风险高的一天。购物作为心情调剂是有效的，但今天它更可能导致之后的财务后悔。购物推迟到明天——24小时后如果仍然想要，那时才是真正需要的。时间是你最好的购物顾问。', ja: '衝動買いの危険が高い日です。ショッピングが気分転換になることは分かりますが、今日はそれが後の財政的な後悔につながる可能性が高いです。ショッピングは明日に延期してください——24時間後もまだ欲しければ、その時は本当に必要なものでしょう。', es: 'Alto riesgo de compras impulsivas hoy—y aunque las compras pueden sentirse como un impulso de ánimo, hoy ese alivio temporal probablemente creará arrepentimiento financiero después. Pospón las compras hasta mañana. Si todavía lo quieres en veinticuatro horas, entonces es probablemente una necesidad genuina. El tiempo es tu mejor asesor de compras.' },
      { ko: '자존심 때문에 불필요한 비용을 지출하지 마세요. 진정한 사자자리의 품격은 얼마나 쓰느냐가 아니라, 무엇을 위해 어떻게 쓰느냐에서 나옵니다. 현명함이 진정한 품위이며, 오늘 자신의 가치관에 충실한 소비를 선택하는 것이 가장 왕다운 결정입니다.', en: 'Don\'t spend unnecessarily out of pride today—because true Leo dignity doesn\'t come from how much you spend, but from what you spend on and why. Wisdom is true dignity, and the most royal decision you can make today is to choose spending that reflects your genuine values rather than your desire for external validation. That\'s the king\'s way.', zh: '不要因为自尊心花不必要的钱。真正的狮子座品格不来自花多少，而来自为何而花、如何花。智慧才是真正的品位——今天选择符合自己价值观的消费，是最王者的决定。', ja: 'プライドのために不要な費用を支出しないでください。真の獅子座の品格はどれだけ使うかではなく、何のためにどのように使うかから生まれます。賢さこそが本当の品位であり、今日自分の価値観に忠実な消費を選ぶことが最も王らしい決断です。', es: 'No gastes innecesariamente por orgullo hoy—porque la verdadera dignidad de Leo no viene de cuánto gastas, sino de en qué y por qué. La sabiduría es la verdadera dignidad, y la decisión más real que puedes tomar hoy es elegir gastos que reflejen tus valores genuinos en lugar de tu deseo de validación externa.' },
      { ko: '재정 상태를 정직하게 직시하세요. 숫자를 보는 것이 두렵다는 것은 완전히 정상적인 감정이며, 많은 사람들이 같은 방식으로 회피합니다. 하지만 외면하면 문제가 커질 뿐입니다—오늘 용기 있게 현실을 확인하는 것이, 앞으로 나아갈 수 있는 유일한 출발점이 됩니다.', en: 'Face your financial situation honestly today—the fear of looking at the numbers is completely normal and is shared by many people, so know you are not alone in this. But ignoring it only makes problems grow. Today, courageously checking the reality in front of you becomes the one necessary starting point from which all forward progress becomes possible. You can handle what you find.', zh: '诚实地面对财务状况。害怕看数字是完全正常的情感，许多人都以同样的方式回避，所以知道你并不孤单。但逃避只会让问题变大——今天勇敢地确认现实，是能够向前迈进的唯一出发点。', ja: '財政状態を正直に直視してください。数字を見るのが怖いのは完全に正常な感情であり、多くの人が同じように回避しています。しかし目を背ければ問題が大きくなるだけです——今日勇気を持って現実を確認することが前に進める唯一の出発点となります。', es: 'Enfrenta tu situación financiera honestamente hoy—el miedo a mirar los números es completamente normal y es compartido por muchas personas, así que sabe que no estás solo. Pero ignorarlo solo agranda los problemas. Verificar courageously la realidad hoy se convierte en el único punto de partida necesario desde el cual todo progreso hacia adelante es posible.' },
      { ko: '큰 계약이나 금전 거래는 오늘 서명하지 마세요. 압박을 받거나 빠르게 결정해야 한다는 느낌이 들 수 있지만, 그 압박이 오히려 잠깐 멈춰야 한다는 신호입니다. 하루 더 검토가 필요합니다—오늘 밤 한 번 더 읽어본 후에도 좋게 느껴진다면, 그때 서명해도 절대 늦지 않습니다.', en: 'Don\'t sign big contracts or financial deals today—you may feel pressure to decide quickly, but that very pressure is actually a signal to pause. One more day of review is needed. If you read it again tonight and it still feels right tomorrow, signing then will never be too late—and you\'ll do so with far greater confidence and peace of mind.', zh: '今天不要签署大合同或金钱交易。你可能感受到快速决定的压力，但那种压力本身是暂停的信号。还需要再审查一天——今晚再读一遍，如果明天仍然感觉不错，那时签署绝不会太迟，而且你会以更大的信心和内心平静来签署。', ja: '大きな契約や金銭取引には今日署名しないでください。急いで決める必要があるというプレッシャーを感じるかもしれませんが、そのプレッシャーこそが一時停止すべきシグナルです。もう一日検討が必要です——今夜もう一度読み直して明日も良く感じるなら、その時署名しても絶対遅くはありません。', es: 'No firmes grandes contratos o acuerdos financieros hoy—puedes sentir presión para decidir rápidamente, pero esa misma presión es en realidad una señal para pausar. Se necesita un día más de revisión. Si lo lees de nuevo esta noche y todavía se siente bien mañana, firmar entonces nunca será demasiado tarde—y lo harás con mucha mayor confianza.' },
      { ko: '겉모습을 유지하기 위한 과소비가 쌓이고 있습니다. 사자자리에게 이미지는 중요하지만, 그 이미지가 당신의 재정적 안정을 잠식하고 있다면 진지하게 재고해볼 때가 되었습니다. 지출 구조를 점검하세요—진정한 사자의 위엄은 화려함에서가 아니라 자신감과 내면의 풍요로움에서 나옵니다.', en: 'Overspending to maintain appearances is accumulating, and while image truly matters to Leo, when that image is eroding your financial stability it is time for honest reassessment. Review your spending structure carefully. True Leo dignity does not come from external grandeur—it radiates from inner confidence and genuine abundance. That inner wealth is what truly impresses people.', zh: '为维持外表的过度消费在累积。对狮子座来说形象确实重要，但当那个形象侵蚀财务稳定性时，就是认真重新思考的时候了。检查支出结构——真正的狮子威严不来自华丽，而来自内心的自信和真实的丰盛。', ja: '見た目を維持するための過剰消費が積み重なっています。獅子座にとってイメージは重要ですが、そのイメージが財政的安定を侵食しているなら真剣に再考する時期です。支出構造を点検してください——真の獅子の威厳は華やかさからではなく自信と内なる豊かさから生まれます。', es: 'El gasto excesivo para mantener apariencias se acumula, y aunque la imagen verdaderamente importa para Leo, cuando esa imagen está erosionando tu estabilidad financiera es tiempo de una reevaluación honesta. Revisa tu estructura de gastos cuidadosamente. La verdadera dignidad de Leo no viene de la grandeza externa—irradia desde la confianza interior y la abundancia genuina.' },
      { ko: '남에게 보여주기 위한 소비를 멈추면 진정한 풍요가 찾아옵니다. 다른 사람의 시선을 위해 돈을 쓰는 것은 결코 당신의 잘못이 아닙니다—우리 모두는 그런 압박을 느낍니다. 하지만 당신이 진정으로 소중히 여기는 것에만 돈을 쓰기 시작하면, 그때 비로소 재정적 자유가 가능해지고 내면에서 진짜 풍요가 시작됩니다.', en: 'When you stop spending to impress others, true abundance arrives—and spending for external validation is never purely your fault, as we all experience that pressure. But when you begin directing money only toward what you genuinely treasure, financial freedom becomes possible and real internal abundance begins. The shift from external to internal—that is where Leo\'s wealth truly lives.', zh: '停止为了给别人看的消费，真正的富足就会到来。为他人眼光花钱绝不是你的错——我们都感受到那种压力。但当你开始只把钱花在真正珍视的事物上时，财务自由才成为可能，内心真正的丰盛才开始。从外在到内在的转变——那才是狮子座财富真正所在之处。', ja: '人に見せるための消費を止めれば真の豊かさが訪れます。外部の承認のためにお金を使うことは決してあなただけの失敗ではありません——私たちは皆そのようなプレッシャーを感じます。しかし本当に大切なものにだけお金を使い始めると、財政的自由が可能になり内なる真の豊かさが始まります。', es: 'Cuando dejas de gastar para impresionar a otros, la verdadera abundancia llega—y gastar para validación externa nunca es puramente tu culpa, ya que todos experimentamos esa presión. Pero cuando empiezas a dirigir el dinero solo hacia lo que genuinamente valoras, la libertad financiera se vuelve posible y comienza la abundancia interna real. Ese es el verdadero hogar de la riqueza de Leo.' },
    ],
  },
};
